export enum ShippingStatus {
  PENDING = 'pending',
  PROCESSING = 'processing',
  SHIPPED = 'shipped',
  DELIVERED = 'delivered',
  CANCELLED = 'cancelled'
}

export enum PaymentStatus {
  PENDING = 'pending',
  PAID = 'paid',
  FAILED = 'failed'
}

export interface Product {
  id: number;
  name: string;
  slug: string;
  sku: string;
  description: string;
  price: number;
  sale_price?: number;
  stock: number;
  category: string;
  image: string;
  is_featured?: boolean;
}

export interface Category {
  id: number;
  name: string;
  slug: string;
  image: string;
}

export interface CartItem extends Product {
  quantity: number;
}

export interface Order {
  id: number;
  orderNumber: string;
  customerName: string;
  phone: string;
  address: string;
  area: string;
  totalAmount: number;
  shippingCost: number;
  paymentStatus: PaymentStatus;
  shippingStatus: ShippingStatus;
  items: CartItem[];
  createdAt: string;
}

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const generateSmartDescription = async (productName: string): Promise<string> => {
  if (!process.env.API_KEY) return `Premium ${productName} specifically crafted for the high-end Bangladeshi market.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Write a compelling 20-word e-commerce product description for a premium product named "${productName}". Target Bangladeshi urban youth. Use an exciting, high-quality tone.`,
    });
    return response.text || "Discover our latest premium collection.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return `Discover the ultimate experience with ${productName}.`;
  }
};

