export default Navbar;

import React from 'react';
import { ShoppingCart, Plus } from 'lucide-react';
import { Product } from '../types';

interface ProductCardProps {
  product: Product;
  onAddToCart: (p: Product) => void;
  onViewDetails: (p: Product) => void;
}

const ProductCard: React.FC<ProductCardProps> = ({ product, onAddToCart, onViewDetails }) => {
  const discount = product.sale_price ? Math.round(((product.price - product.sale_price) / product.price) * 100) : null;

  return (
    <div className="group bg-white rounded-2xl border border-slate-100 overflow-hidden hover:shadow-xl hover:shadow-indigo-500/5 transition-all duration-300 transform hover:-translate-y-1">
      <div className="relative aspect-square overflow-hidden bg-slate-50">
        <img 
          src={product.image} 
          alt={product.name} 
          className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110"
        />
        {discount && (
          <div className="absolute top-3 left-3 bg-red-500 text-white text-[10px] font-bold px-2 py-1 rounded-full uppercase tracking-wider">
            {discount}% OFF
          </div>
        )}
        <button 
          onClick={(e) => { e.stopPropagation(); onAddToCart(product); }}
          className="absolute bottom-4 right-4 bg-white/90 backdrop-blur-md p-3 rounded-full shadow-lg text-indigo-600 opacity-0 translate-y-4 group-hover:opacity-100 group-hover:translate-y-0 transition-all duration-300 hover:bg-indigo-600 hover:text-white"
        >
          <Plus size={20} />
        </button>
      </div>
      <div className="p-4 cursor-pointer" onClick={() => onViewDetails(product)}>
        <p className="text-[10px] font-bold text-indigo-600 uppercase tracking-widest mb-1">{product.category}</p>
        <h3 className="text-sm font-semibold text-slate-800 line-clamp-1 group-hover:text-indigo-600 transition-colors">{product.name}</h3>
        <div className="mt-2 flex items-center gap-2">
          {product.sale_price ? (
            <>
              <span className="text-base font-bold text-slate-900">৳{product.sale_price}</span>
              <span className="text-xs text-slate-400 line-through">৳{product.price}</span>
            </>
          ) : (
            <span className="text-base font-bold text-slate-900">৳{product.price}</span>
          )}
        </div>
      </div>
    </div>
  );
};

export default ProductCard;

import React, { useState, useMemo, useEffect } from 'react';
import { ShoppingBag, X, CheckCircle, ChevronRight, MapPin, Phone, User, CreditCard, ArrowRight, Zap, Info } from 'lucide-react';
import Navbar from './components/Navbar';
import ProductCard from './components/ProductCard';
import AdminPanel from './components/AdminPanel';
import { PRODUCTS, CATEGORIES } from './constants';
import { Product, CartItem, ShippingStatus, PaymentStatus } from './types';
import { generateSmartDescription } from './services/geminiService';

const App: React.FC = () => {
  const [isAdmin, setIsAdmin] = useState(false);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [selectedCategory, setSelectedCategory] = useState<string | null>(null);
  const [isCheckoutOpen, setIsCheckoutOpen] = useState(false);
  const [viewingProduct, setViewingProduct] = useState<Product | null>(null);
  const [smartDesc, setSmartDesc] = useState<string | null>(null);

  // Form states
  const [shippingArea, setShippingArea] = useState<'Inside Dhaka' | 'Outside Dhaka'>('Inside Dhaka');
  const [formData, setFormData] = useState({ name: '', phone: '', address: '' });

  const filteredProducts = useMemo(() => {
    if (!selectedCategory) return PRODUCTS;
    return PRODUCTS.filter(p => p.category === selectedCategory);
  }, [selectedCategory]);

  const subtotal = useMemo(() => cart.reduce((sum, item) => sum + (item.sale_price || item.price) * item.quantity, 0), [cart]);
  const shippingCost = shippingArea === 'Inside Dhaka' ? 60 : 120;
  const total = subtotal + shippingCost;

  const handleAddToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...product, quantity: 1 }];
    });
    setIsCartOpen(true);
  };

  const handleRemoveFromCart = (productId: number) => {
    setCart(prev => prev.filter(item => item.id !== productId));
  };

  const updateQuantity = (productId: number, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === productId) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const handleOpenPDP = async (product: Product) => {
    setViewingProduct(product);
    setSmartDesc("Generating magic description...");
    const desc = await generateSmartDescription(product.name);
    setSmartDesc(desc);
  };

  if (isAdmin) {
    return (
      <>
        <Navbar 
          isAdmin={isAdmin} 
          onAdminToggle={() => setIsAdmin(!isAdmin)} 
          cartCount={cart.length} 
          onCartClick={() => setIsCartOpen(true)} 
        />
        <AdminPanel />
      </>
    );
  }

  return (
    <div className="min-h-screen">
      <Navbar 
        isAdmin={isAdmin} 
        onAdminToggle={() => setIsAdmin(!isAdmin)} 
        cartCount={cart.length} 
        onCartClick={() => setIsCartOpen(true)} 
      />

      {/* Hero Section */}
      <section className="relative overflow-hidden pt-16 pb-20 lg:pt-24 lg:pb-32">
        <div className="absolute top-0 left-1/2 -translate-x-1/2 w-full h-[600px] bg-gradient-to-b from-indigo-50/50 to-transparent -z-10 pointer-events-none" />
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 text-center">
          <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-indigo-50 text-indigo-600 text-xs font-bold uppercase tracking-wider mb-6 border border-indigo-100">
            <Zap size={14} className="fill-indigo-600" />
            Fastest Delivery in Bangladesh
          </div>
          <h1 className="text-4xl sm:text-6xl lg:text-7xl font-extrabold text-slate-900 tracking-tight leading-[1.1]">
            Vibe High. <br />
            <span className="text-indigo-600">Shop Higher.</span>
          </h1>
          <p className="mt-6 text-lg sm:text-xl text-slate-600 max-w-2xl mx-auto font-medium">
            Discover Bangladesh's most premium D2C brands, curated for the modern aesthetic. One-page checkout, zero friction.
          </p>
          <div className="mt-10 flex flex-col sm:flex-row items-center justify-center gap-4">
            <button className="w-full sm:w-auto px-8 py-4 bg-indigo-600 text-white rounded-2xl text-lg font-bold hover:bg-indigo-700 transition-all transform hover:scale-105 shadow-xl shadow-indigo-200">
              Explore Collections
            </button>
            <button className="w-full sm:w-auto px-8 py-4 bg-white text-slate-900 rounded-2xl text-lg font-bold border border-slate-200 hover:bg-slate-50 transition-all">
              Bestsellers
            </button>
          </div>
        </div>
      </section>

      {/* Categories Grid */}
      <section className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 mb-20">
        <div className="flex items-end justify-between mb-8">
          <div>
            <h2 className="text-2xl font-bold text-slate-900">Shop by Category</h2>
            <p className="text-slate-500 text-sm mt-1">Find exactly what you're looking for</p>
          </div>
        </div>
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 lg:gap-6">
          {CATEGORIES.map(cat => (
            <button 
              key={cat.id} 
              onClick={() => setSelectedCategory(selectedCategory === cat.slug ? null : cat.slug)}
