            >
              <img src={cat.image} className="absolute inset-0 w-full h-full object-cover transition-transform duration-700 group-hover:scale-110" />
              <div className="absolute inset-0 bg-gradient-to-t from-slate-900/80 via-transparent to-transparent" />
              <div className="absolute bottom-4 left-4 right-4 text-left">
                <span className="text-xs font-bold text-indigo-400 uppercase tracking-widest">{cat.id.toString().padStart(2, '0')}</span>
                <h3 className="text-lg font-bold text-white">{cat.name}</h3>
              </div>
            </button>
          ))}
        </div>
      </section>

      {/* Product List */}
      <section className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 mb-20">
        <div className="flex items-center justify-between mb-10">
          <h2 className="text-2xl font-bold text-slate-900">
            {selectedCategory ? `${CATEGORIES.find(c => c.slug === selectedCategory)?.name} Collection` : 'Featured Products'}
          </h2>
          {selectedCategory && (
            <button onClick={() => setSelectedCategory(null)} className="text-sm font-semibold text-indigo-600 flex items-center gap-1 hover:underline">
              Clear Filters <X size={14} />
            </button>
          )}
        </div>
        <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 sm:gap-6 lg:gap-8">
          {filteredProducts.map(product => (
            <ProductCard 
              key={product.id} 
              product={product} 
              onAddToCart={handleAddToCart} 
              onViewDetails={handleOpenPDP}
            />
          ))}
        </div>
      </section>

      {/* Cart Drawer */}
      {isCartOpen && (
        <div className="fixed inset-0 z-[60] flex justify-end">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm transition-opacity" onClick={() => setIsCartOpen(false)} />
          <div className="relative w-full max-w-md bg-white h-full shadow-2xl flex flex-col animate-slide-in-right">
            <div className="p-6 border-b border-slate-100 flex items-center justify-between">
              <h2 className="text-xl font-bold text-slate-900 flex items-center gap-2">
                <ShoppingBag size={22} className="text-indigo-600" />
                Shopping Bag
              </h2>
              <button onClick={() => setIsCartOpen(false)} className="p-2 hover:bg-slate-100 rounded-full transition-all">
                <X size={20} />
              </button>
            </div>

            <div className="flex-1 overflow-y-auto p-6">
              {cart.length === 0 ? (
                <div className="h-full flex flex-col items-center justify-center text-center">
                  <div className="w-20 h-20 bg-slate-50 rounded-full flex items-center justify-center mb-4">
                    <ShoppingBag size={32} className="text-slate-300" />
                  </div>
                  <h3 className="text-lg font-bold text-slate-800">Your bag is empty</h3>
                  <p className="text-slate-500 text-sm mt-1 max-w-[200px]">Looks like you haven't added any vibe to your bag yet.</p>
                  <button onClick={() => setIsCartOpen(false)} className="mt-6 px-6 py-2 bg-indigo-600 text-white rounded-xl font-bold text-sm">Start Shopping</button>
                </div>
              ) : (
                <div className="space-y-6">
                  {cart.map(item => (
                    <div key={item.id} className="flex gap-4">
                      <div className="w-20 h-20 rounded-xl overflow-hidden bg-slate-50 flex-shrink-0">
                        <img src={item.image} className="w-full h-full object-cover" />
                      </div>
                      <div className="flex-1">
                        <h4 className="font-bold text-slate-800 leading-tight">{item.name}</h4>
                        <p className="text-sm font-bold text-indigo-600 mt-1">৳{item.sale_price || item.price}</p>
                        <div className="flex items-center justify-between mt-3">
                          <div className="flex items-center gap-3 bg-slate-100 px-3 py-1 rounded-lg">
                            <button onClick={() => updateQuantity(item.id, -1)} className="text-slate-600 hover:text-indigo-600">-</button>
                            <span className="text-sm font-bold w-4 text-center">{item.quantity}</span>
                            <button onClick={() => updateQuantity(item.id, 1)} className="text-slate-600 hover:text-indigo-600">+</button>
                          </div>
                          <button onClick={() => handleRemoveFromCart(item.id)} className="text-xs font-bold text-red-500 hover:underline">Remove</button>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>

            {cart.length > 0 && (
              <div className="p-6 border-t border-slate-100 bg-slate-50/50">
                <div className="flex items-center justify-between mb-2">
                  <span className="text-sm text-slate-500 font-medium">Subtotal</span>
                  <span className="text-base font-bold text-slate-900">৳{subtotal}</span>
                </div>
                <div className="flex items-center justify-between mb-6">
                  <span className="text-sm text-slate-500 font-medium">Shipping</span>
                  <span className="text-xs text-indigo-600 font-bold">Calculated at checkout</span>
                </div>
                <button 
                  onClick={() => { setIsCartOpen(false); setIsCheckoutOpen(true); }}
                  className="w-full bg-slate-900 text-white py-4 rounded-2xl font-bold text-lg flex items-center justify-center gap-2 hover:bg-slate-800 transition-all"
                >
                  Checkout Now <ArrowRight size={20} />
                </button>
              </div>
            )}
          </div>
        </div>
      )}

      {/* One-Page Checkout Modal */}
      {isCheckoutOpen && (
        <div className="fixed inset-0 z-[70] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-md" onClick={() => setIsCheckoutOpen(false)} />
          <div className="relative w-full max-w-4xl bg-white rounded-[2.5rem] shadow-2xl overflow-hidden flex flex-col md:flex-row max-h-[90vh]">
