                      />
                    </div>
                    <div className="relative">
                      <Phone size={18} className="absolute left-4 top-4 text-slate-400" />
                      <input 
                        type="tel" 
                        placeholder="Phone Number (e.g. 017...)" 
                        className="w-full bg-slate-50 border border-slate-200 rounded-2xl py-4 pl-12 pr-4 focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all outline-none font-medium" 
                      />
                    </div>
                    <div className="relative">
                      <MapPin size={18} className="absolute left-4 top-4 text-slate-400" />
                      <textarea 
                        placeholder="Full Address (House, Road, Area)" 
                        className="w-full bg-slate-50 border border-slate-200 rounded-2xl py-4 pl-12 pr-4 focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all outline-none font-medium min-h-[100px]" 
                      />
                    </div>
