                </div>

                <div>
                  <label className="text-xs font-bold text-slate-500 uppercase tracking-widest block mb-2">Select Your Area</label>
                  <div className="grid grid-cols-2 gap-4">
                    <button 
                      onClick={() => setShippingArea('Inside Dhaka')}
                      className={`p-4 rounded-2xl border-2 flex flex-col items-center justify-center transition-all ${shippingArea === 'Inside Dhaka' ? 'border-indigo-600 bg-indigo-50/50' : 'border-slate-100 bg-slate-50 hover:bg-slate-100'}`}
                    >
                      <span className="text-sm font-bold text-slate-800">Inside Dhaka</span>
                      <span className="text-xs font-bold text-indigo-600">৳60</span>
                    </button>
                    <button 
                      onClick={() => setShippingArea('Outside Dhaka')}
                      className={`p-4 rounded-2xl border-2 flex flex-col items-center justify-center transition-all ${shippingArea === 'Outside Dhaka' ? 'border-indigo-600 bg-indigo-50/50' : 'border-slate-100 bg-slate-50 hover:bg-slate-100'}`}
                    >
                      <span className="text-sm font-bold text-slate-800">Outside Dhaka</span>
                      <span className="text-xs font-bold text-indigo-600">৳120</span>
                    </button>
                  </div>
                </div>

                <div>
                  <label className="text-xs font-bold text-slate-500 uppercase tracking-widest block mb-2">Payment Method</label>
                  <div className="p-4 rounded-2xl border-2 border-slate-200 flex items-center justify-between">
                    <div className="flex items-center gap-3">
                      <CreditCard size={20} className="text-slate-400" />
                      <div>
                        <p className="text-sm font-bold text-slate-800">Online Payment / COD</p>
                        <p className="text-[10px] text-slate-500 font-medium italic">bKash, Nagad, Visa, Mastercard supported</p>
                      </div>
                    </div>
                    <CheckCircle size={20} className="text-indigo-600" />
                  </div>
                </div>
              </div>
            </div>

            <div className="w-full md:w-[350px] bg-indigo-600 p-8 lg:p-12 text-white flex flex-col">
              <h3 className="text-xl font-bold mb-8">Order Summary</h3>
              <div className="flex-1 space-y-4">
                {cart.map(item => (
                  <div key={item.id} className="flex justify-between items-start gap-2">
                    <span className="text-sm text-indigo-100 flex-1">{item.quantity}x {item.name}</span>
                    <span className="text-sm font-bold whitespace-nowrap">৳{(item.sale_price || item.price) * item.quantity}</span>
