              </div>
              <div className="mt-8 pt-8 border-t border-indigo-400/30 space-y-3">
                <div className="flex justify-between text-sm">
                  <span className="text-indigo-100">Subtotal</span>
                  <span className="font-bold">৳{subtotal}</span>
                </div>
