import { Product } from '../types';
import { PRODUCTS } from '../constants';

const API_BASE_URL = 'http://localhost:8000/api';

/**
 * ProductService: High-performance data fetching for the Vibe-Store.
 * In a real Next.js environment, we would use 'use cache' or fetch tags.
 */
export const ProductService = {
  /**
   * Fetch all products from Laravel API.
   * Falls back to mock data if API is unavailable.
   */
  async getAllProducts(params?: { category?: string }): Promise<Product[]> {
    try {
      const url = new URL(`${API_BASE_URL}/products`);
      if (params?.category) url.searchParams.append('category', params.category);

      const response = await fetch(url.toString(), {
        next: { revalidate: 3600 }, // Next.js 15 ISR simulation
      } as any);

      if (!response.ok) throw new Error('Network response was not ok');
      return await response.json();
    } catch (error) {
      console.warn('ProductService: Falling back to local state (API connection refused).');
      // Simulate network delay for that premium feel
      await new Promise(resolve => setTimeout(resolve, 800));

      if (params?.category) {
        return PRODUCTS.filter(p => p.category === params.category);
      }
      return PRODUCTS;
    }
  },

  /**
   * Fetch a single product detail by slug.
   */
  async getProductBySlug(slug: string): Promise<Product | null> {
    try {
      const response = await fetch(`${API_BASE_URL}/products/${slug}`);
      if (!response.ok) return null;
      return await response.json();
    } catch (error) {
      return PRODUCTS.find(p => p.slug === slug) || null;
    }
  },

  /**
   * Search products instantly.
   */
  async searchProducts(query: string): Promise<Product[]> {
    try {
      const response = await fetch(`${API_BASE_URL}/products/search?q=${query}`);
      return await response.json();
    } catch (error) {
      return PRODUCTS.filter(p => 
        p.name.toLowerCase().includes(query.toLowerCase()) || 
        p.description.toLowerCase().includes(query.toLowerCase())
      );
    }
  }
};

