        {currentRoute.type === 'success' && (
          <motion.div key="success" initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} className="min-h-[80vh] flex items-center justify-center p-6">
            <div className="max-w-md w-full text-center">
              <div className="w-24 h-24 bg-green-50 text-green-500 rounded-full flex items-center justify-center mx-auto mb-8 shadow-inner">
                <CheckCircle size={48} />
              </div>
              <h1 className="text-4xl font-extrabold text-slate-900 mb-4">Vibe Secured!</h1>
              <p className="text-slate-600 font-medium mb-8">Order <span className="text-indigo-600 font-bold">#{currentRoute.orderId}</span> is now being processed. You will receive an SMS confirmation shortly.</p>
              <div className="flex flex-col gap-3">
                <button onClick={navigateHome} className="w-full bg-slate-900 text-white py-4 rounded-2xl font-bold flex items-center justify-center gap-2">
                  <Home size={18} /> Back to Home
                </button>
                <button className="w-full bg-white text-slate-900 border border-slate-200 py-4 rounded-2xl font-bold flex items-center justify-center gap-2">
                  <ShoppingCart size={18} /> View My Orders
                </button>
              </div>
            </div>
          </motion.div>
        )}

        {currentRoute.type === 'failed' && (
          <motion.div key="failed" initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} className="min-h-[80vh] flex items-center justify-center p-6">
            <div className="max-w-md w-full text-center">
              <div className="w-24 h-24 bg-red-50 text-red-500 rounded-full flex items-center justify-center mx-auto mb-8 shadow-inner">
                <AlertCircle size={48} />
              </div>
              <h1 className="text-4xl font-extrabold text-slate-900 mb-4">Payment Failed</h1>
              <p className="text-slate-600 font-medium mb-8">We couldn't capture your vibe. Reason: <span className="text-red-500 font-bold capitalize">{currentRoute.reason.replace('_', ' ')}</span></p>
              <div className="flex flex-col gap-3">
                <button onClick={() => { setIsCheckoutOpen(true); navigateHome(); }} className="w-full bg-indigo-600 text-white py-4 rounded-2xl font-bold">
                  Try Again
                </button>
                <button onClick={navigateHome} className="w-full bg-white text-slate-900 border border-slate-200 py-4 rounded-2xl font-bold">
                  Back to Store
                </button>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      <WhatsAppButton />

      {/* Cart Drawer */}
      <AnimatePresence>
        {isCartOpen && (
          <div className="fixed inset-0 z-[60] flex justify-end">
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={() => setIsCartOpen(false)} />
            <motion.div initial={{ x: '100%' }} animate={{ x: 0 }} exit={{ x: '100%' }} transition={{ type: 'spring', damping: 30, stiffness: 300 }} className="relative w-full max-w-md bg-white h-full shadow-2xl flex flex-col">
              <div className="p-6 border-b border-slate-100 flex items-center justify-between">
                <h2 className="text-xl font-bold text-slate-900 flex items-center gap-2"><ShoppingBag size={22} className="text-indigo-600" /> Shopping Bag</h2>
                <button onClick={() => setIsCartOpen(false)} className="p-2 hover:bg-slate-100 rounded-full transition-all"><X size={20} /></button>
              </div>
              <div className="flex-1 overflow-y-auto p-6">
                {cart.length === 0 ? (
                  <div className="h-full flex flex-col items-center justify-center text-center">
                    <div className="w-20 h-20 bg-slate-50 rounded-full flex items-center justify-center mb-4"><ShoppingBag size={32} className="text-slate-300" /></div>
                    <h3 className="text-lg font-bold text-slate-800">Your bag is empty</h3>
                    <p className="text-slate-500 text-sm mt-1 max-w-[200px]">Looks like you haven't added any vibe to your bag yet.</p>
                    <button onClick={() => setIsCartOpen(false)} className="mt-6 px-6 py-2 bg-indigo-600 text-white rounded-xl font-bold text-sm">Start Shopping</button>
                  </div>
                ) : (
                  <div className="space-y-6">
                    {cart.map(item => (
                      <div key={item.id} className="flex gap-4">
                        <div className="w-20 h-20 rounded-xl overflow-hidden bg-slate-50 flex-shrink-0">
                          <img src={item.image} className="w-full h-full object-cover" />
                        </div>
                        <div className="flex-1">
                          <h4 className="font-bold text-slate-800 leading-tight">{item.name}</h4>
                          <p className="text-sm font-bold text-indigo-600 mt-1">৳{item.sale_price || item.price}</p>
                          <div className="flex items-center justify-between mt-3">
                            <div className="flex items-center gap-3 bg-slate-100 px-3 py-1 rounded-lg">
                              <button onClick={() => updateQuantity(item.id, -1)} className="text-slate-600 hover:text-indigo-600 font-bold">-</button>
                              <span className="text-sm font-bold w-4 text-center">{item.quantity}</span>
                              <button onClick={() => updateQuantity(item.id, 1)} className="text-slate-600 hover:text-indigo-600 font-bold">+</button>
                            </div>
                            <button onClick={() => handleRemoveFromCart(item.id)} className="text-xs font-bold text-red-500 hover:underline">Remove</button>
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </div>
              {cart.length > 0 && (
                <div className="p-6 border-t border-slate-100 bg-slate-50/50">
                  <div className="flex justify-between mb-2"><span className="text-sm text-slate-500 font-medium">Subtotal</span><span className="text-base font-bold text-slate-900">৳{subtotal}</span></div>
                  <button onClick={() => { setIsCartOpen(false); setIsCheckoutOpen(true); }} className="w-full bg-slate-900 text-white py-4 rounded-2xl font-bold text-lg flex items-center justify-center gap-2 hover:bg-slate-800 transition-all shadow-xl shadow-slate-200">Checkout Now <ArrowRight size={20} /></button>
                </div>
              )}
            </motion.div>
          </div>
        )}
      </AnimatePresence>

      {/* One-Page Checkout Modal */}
      <AnimatePresence>
        {isCheckoutOpen && (
          <div className="fixed inset-0 z-[70] flex items-center justify-center p-4">
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="absolute inset-0 bg-slate-900/60 backdrop-blur-md" onClick={() => !isSubmitting && setIsCheckoutOpen(false)} />
            <motion.div initial={{ scale: 0.9, opacity: 0, y: 20 }} animate={{ scale: 1, opacity: 1, y: 0 }} exit={{ scale: 0.9, opacity: 0, y: 20 }} className="relative w-full max-w-4xl bg-white rounded-[2.5rem] shadow-2xl overflow-hidden flex flex-col md:flex-row max-h-[90vh]">
              <div className="flex-1 p-8 lg:p-12 overflow-y-auto">
                <h2 className="text-3xl font-bold text-slate-900 mb-8">Secure Checkout</h2>
                {error && <div className="mb-6 p-4 bg-red-50 border border-red-100 rounded-2xl flex items-center gap-3 text-red-600 text-sm font-bold"><AlertCircle size={18} />{error}</div>}
                <div className="space-y-6">
                  <div>
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-widest block mb-2">Shipping Information</label>
                    <div className="grid gap-4">
                      <div className="relative"><User size={18} className="absolute left-4 top-4 text-slate-400" /><input type="text" placeholder="Full Name" value={formData.customer_name} onChange={(e) => setFormData({...formData, customer_name: e.target.value})} className="w-full bg-slate-50 border border-slate-200 rounded-2xl py-4 pl-12 pr-4 outline-none font-medium" /></div>
                      <div className="relative"><Phone size={18} className="absolute left-4 top-4 text-slate-400" /><input type="tel" placeholder="Phone (e.g. 01712345678)" value={formData.phone} onChange={(e) => setFormData({...formData, phone: e.target.value})} className="w-full bg-slate-50 border border-slate-200 rounded-2xl py-4 pl-12 pr-4 outline-none font-medium" /></div>
                      <div className="relative"><MapPin size={18} className="absolute left-4 top-4 text-slate-400" /><textarea placeholder="Full Delivery Address" value={formData.address} onChange={(e) => setFormData({...formData, address: e.target.value})} className="w-full bg-slate-50 border border-slate-200 rounded-2xl py-4 pl-12 pr-4 outline-none font-medium min-h-[100px]" /></div>
                    </div>
                  </div>
                  <div>
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-widest block mb-2">Shipping Area</label>
                    <div className="grid grid-cols-2 gap-4">
                      <button onClick={() => setFormData({...formData, area: 'Inside Dhaka'})} className={`p-4 rounded-2xl border-2 transition-all ${formData.area === 'Inside Dhaka' ? 'border-indigo-600 bg-indigo-50/50' : 'border-slate-100 bg-slate-50'}`}><span className="text-sm font-bold">Inside Dhaka</span><br/><span className="text-xs font-bold text-indigo-600">৳60</span></button>
                      <button onClick={() => setFormData({...formData, area: 'Outside Dhaka'})} className={`p-4 rounded-2xl border-2 transition-all ${formData.area === 'Outside Dhaka' ? 'border-indigo-600 bg-indigo-50/50' : 'border-slate-100 bg-slate-50'}`}><span className="text-sm font-bold">Outside Dhaka</span><br/><span className="text-xs font-bold text-indigo-600">৳120</span></button>
                    </div>
                  </div>
                </div>
              </div>
              <div className="w-full md:w-[350px] bg-slate-900 p-8 lg:p-12 text-white flex flex-col">
                <h3 className="text-xl font-bold mb-8">Summary</h3>
                <div className="flex-1 space-y-4 max-h-[250px] overflow-y-auto pr-2 custom-scrollbar">
                  {cart.map(item => (<div key={item.id} className="flex justify-between items-start gap-2"><span className="text-sm text-slate-400 flex-1">{item.quantity}x {item.name}</span><span className="text-sm font-bold">৳{(item.sale_price || item.price) * item.quantity}</span></div>))}
                </div>
                <div className="mt-8 pt-8 border-t border-slate-800 space-y-3">
                  <div className="flex justify-between text-sm text-slate-400"><span>Shipping</span><span>৳{shippingCost}</span></div>
                  <div className="flex justify-between text-2xl font-bold pt-4 text-indigo-400"><span>Total</span><span>৳{total}</span></div>
                </div>
                <button disabled={isSubmitting} onClick={handlePlaceOrder} className="w-full bg-indigo-600 text-white py-4 rounded-2xl font-bold text-lg mt-8 shadow-xl hover:bg-indigo-500 disabled:opacity-70 flex items-center justify-center gap-2">
                  {isSubmitting ? <><Loader2 size={20} className="animate-spin" /> Processing...</> : <>Confirm Order</>}
                </button>
                <p className="text-[10px] text-center mt-4 text-slate-500 font-bold uppercase tracking-widest">Powered by aamarPay</p>
              </div>
              <button onClick={() => setIsCheckoutOpen(false)} className="absolute top-6 right-6 p-2 bg-slate-100 rounded-full text-slate-900"><X size={20} /></button>
            </motion.div>
          </div>
        )}
      </AnimatePresence>
    </div>
  );
};

export default App;

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { ShoppingBag, X, CheckCircle, MapPin, Phone, User, ArrowRight, Zap, Loader2, AlertCircle, Home, ShoppingCart } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import Navbar from './components/Navbar';
import ProductGrid from './components/ProductGrid';
import AdminPanel from './components/AdminPanel';
import ProductDetailsPage from './components/ProductDetailsPage';
import WhatsAppButton from './components/WhatsAppButton';
import { CATEGORIES } from './constants';
import { Product, CartItem } from './types';
import { ProductService } from './services/productService';

type Route = 
  | { type: 'home' } 
  | { type: 'product', product: Product }
  | { type: 'success', orderId: string }
  | { type: 'failed', reason: string };

const App: React.FC = () => {
  const [isAdmin, setIsAdmin] = useState(false);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [selectedCategory, setSelectedCategory] = useState<string | null>(null);
  const [isCheckoutOpen, setIsCheckoutOpen] = useState(false);
  const [currentRoute, setCurrentRoute] = useState<Route>({ type: 'home' });
  // Fix: Changed Ref type from HTMLElement to HTMLDivElement to match the target <div> element on line 185
  const productsSectionRef = useRef<HTMLDivElement>(null);

  // Check for URL parameters on mount (Success/Fail redirects)
  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const orderId = params.get('order_id');
    const status = params.get('status');
    const reason = params.get('reason') || params.get('error');

    if (window.location.pathname === '/order-success' || (orderId && status === 'paid')) {
      setCurrentRoute({ type: 'success', orderId: orderId || 'N/A' });
      setCart([]); // Clear cart on success
    } else if (window.location.pathname === '/order-failed' || reason) {
      setCurrentRoute({ type: 'failed', reason: reason || 'Payment could not be processed' });
    }
  }, []);

  // Checkout Form States
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [formData, setFormData] = useState({
    customer_name: '',
    phone: '',
    address: '',
    area: 'Inside Dhaka' as 'Inside Dhaka' | 'Outside Dhaka'
  });

  const subtotal = useMemo(() => cart.reduce((sum, item) => sum + (item.sale_price || item.price) * item.quantity, 0), [cart]);
  const shippingCost = formData.area === 'Inside Dhaka' ? 60 : 120;
  const total = subtotal + shippingCost;

  const handleAddToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...product, quantity: 1 }];
    });
    setIsCartOpen(true);
  };

  const updateQuantity = (productId: number, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === productId) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const handleRemoveFromCart = (productId: number) => {
    setCart(prev => prev.filter(item => item.id !== productId));
  };

  const validateForm = () => {
    if (!formData.customer_name.trim()) return "Please enter your full name";
    const phoneRegex = /^(?:\+88|88)?(01[3-9]\d{8})$/;
    if (!phoneRegex.test(formData.phone)) return "Please enter a valid BD phone number (e.g. 01712345678)";
    if (formData.address.length < 10) return "Please enter a detailed delivery address";
    return null;
  };

  const handlePlaceOrder = async () => {
    const validationError = validateForm();
    if (validationError) {
      setError(validationError);
      return;
    }

    setError(null);
    setIsSubmitting(true);

    const orderData = {
      ...formData,
      items: cart.map(item => ({
        product_id: item.id,
        quantity: item.quantity
      }))
    };

    const result = await ProductService.createOrder(orderData);

    if (result.success && result.payment_url) {
      // Final production logic: Redirect to real aamarPay/SSLCommerz gateway
      window.location.href = result.payment_url!;
    } else {
      setError(result.message || "Failed to process order. Please try again.");
      setIsSubmitting(false);
    }
  };

  const navigateToProduct = (product: Product) => {
    setCurrentRoute({ type: 'product', product });
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const navigateHome = () => {
    window.history.replaceState({}, '', '/');
    setCurrentRoute({ type: 'home' });
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const scrollToProducts = () => {
    productsSectionRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' });
  };

  if (isAdmin) {
    return (
      <div className="min-h-screen bg-slate-50">
        <Navbar isAdmin={isAdmin} onAdminToggle={() => setIsAdmin(!isAdmin)} cartCount={cart.length} onCartClick={() => setIsCartOpen(true)} />
        <AdminPanel />
      </div>
    );
  }

  return (
    <div className="min-h-screen selection:bg-indigo-100 selection:text-indigo-900">
      <Navbar isAdmin={isAdmin} onAdminToggle={() => setIsAdmin(!isAdmin)} cartCount={cart.length} onCartClick={() => setIsCartOpen(true)} />

      <AnimatePresence mode="wait">
        {currentRoute.type === 'home' && (
          <motion.main key="home" initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}>
            {/* Hero Section */}
            <section className="relative overflow-hidden pt-16 pb-20 lg:pt-24 lg:pb-32">
              <div className="absolute top-0 left-1/2 -translate-x-1/2 w-full h-[600px] bg-gradient-to-b from-indigo-50/50 to-transparent -z-10 pointer-events-none" />
              <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 text-center">
                <motion.div initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-indigo-50 text-indigo-600 text-xs font-bold uppercase tracking-wider mb-6 border border-indigo-100">
                  <Zap size={14} className="fill-indigo-600" /> Fastest Delivery in Bangladesh
                </motion.div>
                <motion.h1 initial={{ y: 20, opacity: 0 }} animate={{ y: 0, opacity: 1 }} transition={{ delay: 0.1 }} className="text-4xl sm:text-6xl lg:text-7xl font-extrabold text-slate-900 tracking-tight leading-[1.1]">
                  Vibe High. <br /> <span className="text-indigo-600">Shop Higher.</span>
                </motion.h1>
                <motion.p initial={{ y: 20, opacity: 0 }} animate={{ y: 0, opacity: 1 }} transition={{ delay: 0.2 }} className="mt-6 text-lg sm:text-xl text-slate-600 max-w-2xl mx-auto font-medium">
                  Discover Bangladesh's most premium D2C brands, curated for the modern aesthetic. One-page checkout, zero friction.
                </motion.p>
                <motion.div initial={{ y: 20, opacity: 0 }} animate={{ y: 0, opacity: 1 }} transition={{ delay: 0.3 }} className="mt-10 flex flex-col sm:flex-row items-center justify-center gap-4">
