import React, { useState, useMemo, useRef, useEffect } from 'react';
import { ShoppingBag, X, CheckCircle, MapPin, Phone, User, ArrowRight, Zap, Loader2, AlertCircle, Home, ShoppingCart, Package, KeyRound } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import Navbar from './components/Navbar';
import ProductGrid from './components/ProductGrid';
import AdminPanel from './components/AdminPanel';
import ProductDetailsPage from './components/ProductDetailsPage';
import WhatsAppButton from './components/WhatsAppButton';
import { CATEGORIES } from './constants';
import { Product, CartItem, Order } from './types';
import { ProductService } from './services/productService';
import { AuthService } from './services/authService';

type Route = 
  | { type: 'home' } 
  | { type: 'product', product: Product }
  | { type: 'success', orderId: string }
  | { type: 'failed', reason: string }
  | { type: 'tracking' };

const App: React.FC = () => {
  const [isAdmin, setIsAdmin] = useState(false);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [selectedCategory, setSelectedCategory] = useState<string | null>(null);
  const [isCheckoutOpen, setIsCheckoutOpen] = useState(false);
  const [currentRoute, setCurrentRoute] = useState<Route>({ type: 'home' });
  const [isLoggedIn, setIsLoggedIn] = useState(AuthService.isLoggedIn());
  const [userOrders, setUserOrders] = useState<Order[]>([]);
  const productsSectionRef = useRef<HTMLDivElement>(null);

  // Tracking States
  const [trackStep, setTrackStep] = useState<'phone' | 'otp' | 'history'>('phone');
  const [trackPhone, setTrackPhone] = useState('');
  const [trackOtp, setTrackOtp] = useState('');
  const [trackLoading, setTrackLoading] = useState(false);
  const [trackError, setTrackError] = useState('');

  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const orderId = params.get('order_id');
    const status = params.get('status');
    const reason = params.get('reason') || params.get('error');

    if (window.location.pathname === '/order-success' || (orderId && status === 'paid')) {
      setCurrentRoute({ type: 'success', orderId: orderId || 'N/A' });
      setCart([]);
    } else if (window.location.pathname === '/order-failed' || reason) {
      setCurrentRoute({ type: 'failed', reason: reason || 'Payment could not be processed' });
    }

    if (isLoggedIn) {
      AuthService.getMyOrders().then(setUserOrders);
    }
  }, [isLoggedIn]);

  // Checkout Form States
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [formData, setFormData] = useState({
    customer_name: '',
    phone: '',
    address: '',
    area: 'Inside Dhaka' as 'Inside Dhaka' | 'Outside Dhaka'
  });

  const subtotal = useMemo(() => cart.reduce((sum, item) => sum + (item.sale_price || item.price) * item.quantity, 0), [cart]);
  const shippingCost = formData.area === 'Inside Dhaka' ? 60 : 120;
  const total = subtotal + shippingCost;

  const handleAddToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...product, quantity: 1 }];
    });
    setIsCartOpen(true);
  };

  const handleSendOtp = async () => {
    if (!/^(?:\+88|88)?(01[3-9]\d{8})$/.test(trackPhone)) {
      setTrackError("Enter a valid BD phone number");
      return;
    }
    setTrackLoading(true);
    setTrackError("");
    const res = await AuthService.sendOtp(trackPhone);
    setTrackLoading(false);
    if (res.success) setTrackStep('otp');
    else setTrackError(res.message);
  };

  const handleVerifyOtp = async () => {
    if (trackOtp.length !== 4) {
      setTrackError("Enter 4-digit code");
      return;
    }
    setTrackLoading(true);
    setTrackError("");
    const res = await AuthService.verifyOtp(trackPhone, trackOtp);
    setTrackLoading(false);
    if (res.success) {
      setIsLoggedIn(true);
      setTrackStep('history');
      const orders = await AuthService.getMyOrders();
      setUserOrders(orders);
    } else {
      setTrackError(res.message || "Verification failed");
    }
  };

  const updateQuantity = (productId: number, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === productId) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const handlePlaceOrder = async () => {
    if (!formData.customer_name.trim()) { setError("Name required"); return; }
    if (!/^(?:\+88|88)?(01[3-9]\d{8})$/.test(formData.phone)) { setError("Invalid phone"); return; }
    if (formData.address.length < 10) { setError("Address too short"); return; }

    setError(null);
    setIsSubmitting(true);
    const result = await ProductService.createOrder({
      ...formData,
      items: cart.map(item => ({ product_id: item.id, quantity: item.quantity }))
    });
    if (result.success && result.payment_url) {
      window.location.href = result.payment_url!;
    } else {
      setError(result.message);
      setIsSubmitting(false);
    }
  };

  const navigateToProduct = (product: Product) => {
    setCurrentRoute({ type: 'product', product });
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const navigateHome = () => {
    window.history.replaceState({}, '', '/');
    setCurrentRoute({ type: 'home' });
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  if (isAdmin) {
    return (
      <div className="min-h-screen bg-slate-50">
        <Navbar isAdmin={isAdmin} isLoggedIn={isLoggedIn} onAdminToggle={() => setIsAdmin(!isAdmin)} cartCount={cart.length} onCartClick={() => setIsCartOpen(true)} onTrackingClick={() => setCurrentRoute({ type: 'tracking' })} />
        <AdminPanel />
      </div>
    );
  }

  return (
    <div className="min-h-screen selection:bg-indigo-100 selection:text-indigo-900">
      <Navbar isAdmin={isAdmin} isLoggedIn={isLoggedIn} onAdminToggle={() => setIsAdmin(!isAdmin)} cartCount={cart.length} onCartClick={() => setIsCartOpen(true)} onTrackingClick={() => setCurrentRoute({ type: 'tracking' })} />

      <AnimatePresence mode="wait">
        {currentRoute.type === 'home' && (
          <motion.main key="home" initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}>
            {/* Hero Section */}
            <section className="relative overflow-hidden pt-16 pb-20 lg:pt-24 lg:pb-32">
              <div className="absolute top-0 left-1/2 -translate-x-1/2 w-full h-[600px] bg-gradient-to-b from-indigo-50/50 to-transparent -z-10 pointer-events-none" />
              <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 text-center">
                <motion.div initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-indigo-50 text-indigo-600 text-xs font-bold uppercase tracking-wider mb-6 border border-indigo-100">
                  <Zap size={14} className="fill-indigo-600" /> Fastest Delivery in Bangladesh
                </motion.div>
                <motion.h1 className="text-4xl sm:text-6xl lg:text-7xl font-extrabold text-slate-900 tracking-tight leading-[1.1]">Vibe High. <br /> <span className="text-indigo-600">Shop Higher.</span></motion.h1>
                <motion.p className="mt-6 text-lg sm:text-xl text-slate-600 max-w-2xl mx-auto font-medium">Discover Bangladesh's most premium D2C brands, curated for the modern aesthetic.</motion.p>
                <div className="mt-10 flex flex-col sm:flex-row items-center justify-center gap-4">
                  <button onClick={() => productsSectionRef.current?.scrollIntoView({ behavior: 'smooth' })} className="w-full sm:w-auto px-8 py-4 bg-indigo-600 text-white rounded-2xl text-lg font-bold hover:bg-indigo-700 shadow-xl shadow-indigo-200">Explore Collections</button>
                </div>
              </div>
            </section>
            <section className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 mb-20">
              <div className="grid grid-cols-2 md:grid-cols-4 gap-4 lg:gap-6 mb-20">
                {CATEGORIES.map((cat, idx) => (
                  <motion.button key={cat.id} initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: idx * 0.1 }} onClick={() => setSelectedCategory(cat.slug)} className={`group relative aspect-[4/5] rounded-3xl overflow-hidden border-2 transition-all ${selectedCategory === cat.slug ? 'border-indigo-600 scale-95' : 'border-transparent'}`}>
                    <img src={cat.image} className="absolute inset-0 w-full h-full object-cover transition-transform duration-700 group-hover:scale-110" />
                    <div className="absolute inset-0 bg-gradient-to-t from-slate-900/80 via-transparent to-transparent" />
                    <div className="absolute bottom-4 left-4 right-4 text-left"><h3 className="text-lg font-bold text-white">{cat.name}</h3></div>
                  </motion.button>
                ))}
              </div>
              <div ref={productsSectionRef} className="scroll-mt-24">
                <ProductGrid category={selectedCategory} onAddToCart={handleAddToCart} onViewDetails={navigateToProduct} />
              </div>
            </section>
          </motion.main>
        )}

        {currentRoute.type === 'product' && (
          <ProductDetailsPage key="pdp" product={currentRoute.product} onBack={navigateHome} onAddToCart={handleAddToCart} />
        )}

        {currentRoute.type === 'tracking' && (
          <motion.div key="tracking" initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} className="min-h-[80vh] flex items-center justify-center p-6">
            <div className="max-w-md w-full bg-white p-8 rounded-[2.5rem] shadow-2xl border border-slate-100">
              {isLoggedIn || trackStep === 'history' ? (
                <div>
                  <div className="flex items-center justify-between mb-8">
                    <h2 className="text-2xl font-bold text-slate-900">Order History</h2>
                    <button onClick={() => { AuthService.logout(); setIsLoggedIn(false); setTrackStep('phone'); }} className="text-xs font-bold text-red-500 underline">Logout</button>
                  </div>
                  {userOrders.length === 0 ? (
                    <div className="text-center py-10 text-slate-500">No orders found for this account.</div>
                  ) : (
                    <div className="space-y-4">
                      {userOrders.map(order => (
                        <div key={order.id} className="p-4 bg-slate-50 rounded-2xl border border-slate-100">
                          <div className="flex justify-between items-start mb-2">
                            <span className="text-sm font-bold text-indigo-600">#{order.orderNumber}</span>
                            <span className="text-[10px] font-bold uppercase px-2 py-0.5 rounded-full bg-indigo-100 text-indigo-600">{order.shippingStatus}</span>
                          </div>
                          <div className="text-xs text-slate-500">Total: ৳{order.totalAmount} • {new Date(order.createdAt).toLocaleDateString()}</div>
                        </div>
                      ))}
                    </div>
                  )}
                  <button onClick={navigateHome} className="w-full mt-8 bg-slate-900 text-white py-4 rounded-2xl font-bold">Back to Store</button>
                </div>
              ) : (
                <div className="space-y-8">
                  <div className="text-center">
                    <div className="w-16 h-16 bg-indigo-50 text-indigo-600 rounded-full flex items-center justify-center mx-auto mb-4"><Package size={32} /></div>
                    <h2 className="text-2xl font-bold text-slate-900">Track My Order</h2>
                    <p className="text-sm text-slate-500 mt-2">Enter your phone number to see your order status and history.</p>
                  </div>

                  {trackError && <div className="p-3 bg-red-50 text-red-600 text-xs font-bold rounded-xl flex items-center gap-2"><AlertCircle size={14} />{trackError}</div>}

                  {trackStep === 'phone' ? (
                    <div className="space-y-4">
                      <div className="relative">
                        <Phone size={18} className="absolute left-4 top-4 text-slate-400" />
                        <input type="tel" placeholder="01712345678" value={trackPhone} onChange={e => setTrackPhone(e.target.value)} className="w-full bg-slate-50 border border-slate-200 rounded-2xl py-4 pl-12 pr-4 outline-none font-medium" />
                      </div>
                      <button disabled={trackLoading} onClick={handleSendOtp} className="w-full bg-indigo-600 text-white py-4 rounded-2xl font-bold flex items-center justify-center gap-2">
                        {trackLoading ? <Loader2 className="animate-spin" /> : <>Send OTP <ArrowRight size={18} /></>}
                      </button>
                    </div>
                  ) : (
                    <div className="space-y-4">
                      <div className="relative">
                        <KeyRound size={18} className="absolute left-4 top-4 text-slate-400" />
                        <input type="text" maxLength={4} placeholder="Enter 4-digit code" value={trackOtp} onChange={e => setTrackOtp(e.target.value)} className="w-full bg-slate-50 border border-slate-200 rounded-2xl py-4 pl-12 pr-4 outline-none font-medium text-center tracking-[1em]" />
                      </div>
                      <button disabled={trackLoading} onClick={handleVerifyOtp} className="w-full bg-slate-900 text-white py-4 rounded-2xl font-bold flex items-center justify-center gap-2">
                        {trackLoading ? <Loader2 className="animate-spin" /> : <>Verify & Login</>}
                      </button>
                      <button onClick={() => setTrackStep('phone')} className="w-full text-xs font-bold text-slate-400 uppercase tracking-widest">Change Phone Number</button>
                    </div>
                  )}
                </div>
              )}
            </div>
          </motion.div>
        )}

        {/* ... Success/Failed views remain same ... */}
        {currentRoute.type === 'success' && (
          <motion.div key="success" initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} className="min-h-[80vh] flex items-center justify-center p-6">
            <div className="max-w-md w-full text-center">
              <div className="w-24 h-24 bg-green-50 text-green-500 rounded-full flex items-center justify-center mx-auto mb-8 shadow-inner"><CheckCircle size={48} /></div>
              <h1 className="text-4xl font-extrabold text-slate-900 mb-4">Vibe Secured!</h1>
              <p className="text-slate-600 font-medium mb-8">Order <span className="text-indigo-600 font-bold">#{currentRoute.orderId}</span> is now being processed.</p>
              <button onClick={navigateHome} className="w-full bg-slate-900 text-white py-4 rounded-2xl font-bold flex items-center justify-center gap-2"><Home size={18} /> Back to Home</button>
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      <WhatsAppButton />

      {/* Cart Drawer */}
      <AnimatePresence>
        {isCartOpen && (
          <div className="fixed inset-0 z-[60] flex justify-end">
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={() => setIsCartOpen(false)} />
            <motion.div initial={{ x: '100%' }} animate={{ x: 0 }} exit={{ x: '100%' }} transition={{ type: 'spring', damping: 30, stiffness: 300 }} className="relative w-full max-w-md bg-white h-full shadow-2xl flex flex-col">
              <div className="p-6 border-b border-slate-100 flex items-center justify-between">
                <h2 className="text-xl font-bold text-slate-900 flex items-center gap-2"><ShoppingBag size={22} className="text-indigo-600" /> Shopping Bag</h2>
                <button onClick={() => setIsCartOpen(false)} className="p-2 hover:bg-slate-100 rounded-full transition-all"><X size={20} /></button>
              </div>
              <div className="flex-1 overflow-y-auto p-6">
                {cart.length === 0 ? (
                  <div className="h-full flex flex-col items-center justify-center text-center text-slate-500">Bag is empty</div>
                ) : (
                  <div className="space-y-6">
                    {cart.map(item => (
                      <div key={item.id} className="flex gap-4">
                        <div className="w-20 h-20 rounded-xl overflow-hidden bg-slate-50 flex-shrink-0"><img src={item.image} className="w-full h-full object-cover" /></div>
                        <div className="flex-1">
                          <h4 className="font-bold text-slate-800 leading-tight">{item.name}</h4>
                          <p className="text-sm font-bold text-indigo-600 mt-1">৳{item.sale_price || item.price}</p>
                          <div className="flex items-center justify-between mt-3">
                            <div className="flex items-center gap-3 bg-slate-100 px-3 py-1 rounded-lg">
                              <button onClick={() => updateQuantity(item.id, -1)} className="font-bold">-</button>
                              <span className="text-sm font-bold">{item.quantity}</span>
                              <button onClick={() => updateQuantity(item.id, 1)} className="font-bold">+</button>
                            </div>
                            <button onClick={() => handleRemoveFromCart(item.id)} className="text-xs font-bold text-red-500">Remove</button>
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </div>
              {cart.length > 0 && (
                <div className="p-6 border-t border-slate-100 bg-slate-50/50">
                  <div className="flex justify-between mb-4"><span className="text-sm font-medium">Subtotal</span><span className="text-lg font-bold">৳{subtotal}</span></div>
                  <button onClick={() => { setIsCartOpen(false); setIsCheckoutOpen(true); }} className="w-full bg-slate-900 text-white py-4 rounded-2xl font-bold text-lg flex items-center justify-center gap-2">Checkout Now <ArrowRight size={20} /></button>
                </div>
              )}
            </motion.div>
          </div>
        )}
      </AnimatePresence>

      {/* Checkout Modal */}
      <AnimatePresence>
        {isCheckoutOpen && (
          <div className="fixed inset-0 z-[70] flex items-center justify-center p-4">
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="absolute inset-0 bg-slate-900/60 backdrop-blur-md" onClick={() => !isSubmitting && setIsCheckoutOpen(false)} />
            <motion.div initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} exit={{ scale: 0.9, opacity: 0 }} className="relative w-full max-w-4xl bg-white rounded-[2.5rem] shadow-2xl overflow-hidden flex flex-col md:flex-row max-h-[90vh]">
              <div className="flex-1 p-8 overflow-y-auto">
                <h2 className="text-3xl font-bold text-slate-900 mb-8">Secure Checkout</h2>
                {error && <div className="mb-6 p-4 bg-red-50 text-red-600 rounded-2xl text-sm font-bold">{error}</div>}
                <div className="space-y-6">
                  <div className="relative"><User size={18} className="absolute left-4 top-4 text-slate-400" /><input type="text" placeholder="Full Name" value={formData.customer_name} onChange={e => setFormData({...formData, customer_name: e.target.value})} className="w-full bg-slate-50 border border-slate-200 rounded-2xl py-4 pl-12 outline-none" /></div>
                  <div className="relative"><Phone size={18} className="absolute left-4 top-4 text-slate-400" /><input type="tel" placeholder="Phone Number" value={formData.phone} onChange={e => setFormData({...formData, phone: e.target.value})} className="w-full bg-slate-50 border border-slate-200 rounded-2xl py-4 pl-12 outline-none" /></div>
                  <div className="relative"><MapPin size={18} className="absolute left-4 top-4 text-slate-400" /><textarea placeholder="Delivery Address" value={formData.address} onChange={e => setFormData({...formData, address: e.target.value})} className="w-full bg-slate-50 border border-slate-200 rounded-2xl py-4 pl-12 outline-none min-h-[100px]" /></div>
                  <div className="grid grid-cols-2 gap-4">
                    <button onClick={() => setFormData({...formData, area: 'Inside Dhaka'})} className={`p-4 rounded-2xl border-2 transition-all ${formData.area === 'Inside Dhaka' ? 'border-indigo-600 bg-indigo-50' : 'border-slate-100'}`}><span className="font-bold">Inside Dhaka</span><br/><span className="text-xs text-indigo-600">৳60</span></button>
                    <button onClick={() => setFormData({...formData, area: 'Outside Dhaka'})} className={`p-4 rounded-2xl border-2 transition-all ${formData.area === 'Outside Dhaka' ? 'border-indigo-600 bg-indigo-50' : 'border-slate-100'}`}><span className="font-bold">Outside Dhaka</span><br/><span className="text-xs text-indigo-600">৳120</span></button>
                  </div>
                </div>
              </div>
              <div className="w-full md:w-[350px] bg-slate-900 p-8 text-white flex flex-col">
                <h3 className="text-xl font-bold mb-8">Summary</h3>
                <div className="flex-1 space-y-4 overflow-y-auto mb-8 pr-2">
                  {cart.map(item => (<div key={item.id} className="flex justify-between text-sm"><span className="text-slate-400">{item.quantity}x {item.name}</span><span>৳{(item.sale_price || item.price) * item.quantity}</span></div>))}
                </div>
                <div className="border-t border-slate-800 pt-8 space-y-4">
                   <div className="flex justify-between text-sm text-slate-400"><span>Shipping</span><span>৳{shippingCost}</span></div>
                   <div className="flex justify-between text-2xl font-bold text-indigo-400"><span>Total</span><span>৳{total}</span></div>
                </div>
                <button disabled={isSubmitting} onClick={handlePlaceOrder} className="w-full bg-indigo-600 py-4 rounded-2xl font-bold text-lg mt-8 shadow-xl hover:bg-indigo-500 transition-all flex items-center justify-center gap-2">
                  {isSubmitting ? <Loader2 className="animate-spin" /> : <>Confirm Order</>}
                </button>
                <p className="text-[10px] text-center mt-4 text-slate-500 uppercase tracking-widest font-bold">Powered by aamarPay</p>
              </div>
              <button onClick={() => setIsCheckoutOpen(false)} className="absolute top-6 right-6 p-2 bg-slate-100 rounded-full text-slate-900"><X size={20} /></button>
            </motion.div>
          </div>
        )}
      </AnimatePresence>
    </div>
  );
};

export default App;

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { ShoppingBag, X, CheckCircle, MapPin, Phone, User, ArrowRight, Zap, Loader2, AlertCircle, Home, ShoppingCart, Package, KeyRound } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import Navbar from './components/Navbar';
import ProductGrid from './components/ProductGrid';
import AdminPanel from './components/AdminPanel';
import ProductDetailsPage from './components/ProductDetailsPage';
import WhatsAppButton from './components/WhatsAppButton';
import { CATEGORIES } from './constants';
import { Product, CartItem, Order } from './types';
import { ProductService } from './services/productService';
import { AuthService } from './services/authService';

type Route = 
  | { type: 'home' } 
  | { type: 'product', product: Product }
  | { type: 'success', orderId: string }
  | { type: 'failed', reason: string }
  | { type: 'tracking' };

const App: React.FC = () => {
  const [isAdmin, setIsAdmin] = useState(false);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [selectedCategory, setSelectedCategory] = useState<string | null>(null);
  const [isCheckoutOpen, setIsCheckoutOpen] = useState(false);
  const [currentRoute, setCurrentRoute] = useState<Route>({ type: 'home' });
  const [isLoggedIn, setIsLoggedIn] = useState(AuthService.isLoggedIn());
  const [userOrders, setUserOrders] = useState<Order[]>([]);
  const productsSectionRef = useRef<HTMLDivElement>(null);

  // Tracking States
  const [trackStep, setTrackStep] = useState<'phone' | 'otp' | 'history'>('phone');
  const [trackPhone, setTrackPhone] = useState('');
  const [trackOtp, setTrackOtp] = useState('');
  const [trackLoading, setTrackLoading] = useState(false);
  const [trackError, setTrackError] = useState('');

  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const orderId = params.get('order_id');
    const status = params.get('status');
    const reason = params.get('reason') || params.get('error');

    if (window.location.pathname === '/order-success' || (orderId && status === 'paid')) {
      setCurrentRoute({ type: 'success', orderId: orderId || 'N/A' });
      setCart([]);
    } else if (window.location.pathname === '/order-failed' || reason) {
      setCurrentRoute({ type: 'failed', reason: reason || 'Payment could not be processed' });
    }

    if (isLoggedIn) {
      AuthService.getMyOrders().then(setUserOrders);
    }
  }, [isLoggedIn]);

  // Checkout Form States
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [formData, setFormData] = useState({
    customer_name: '',
    phone: '',
    address: '',
    area: 'Inside Dhaka' as 'Inside Dhaka' | 'Outside Dhaka'
  });

  const subtotal = useMemo(() => cart.reduce((sum, item) => sum + (item.sale_price || item.price) * item.quantity, 0), [cart]);
  const shippingCost = formData.area === 'Inside Dhaka' ? 60 : 120;
  const total = subtotal + shippingCost;

  const handleAddToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...product, quantity: 1 }];
    });
    setIsCartOpen(true);
  };

  const handleSendOtp = async () => {
    if (!/^(?:\+88|88)?(01[3-9]\d{8})$/.test(trackPhone)) {
      setTrackError("Enter a valid BD phone number");
      return;
    }
    setTrackLoading(true);
    setTrackError("");
    const res = await AuthService.sendOtp(trackPhone);
    setTrackLoading(false);
    if (res.success) setTrackStep('otp');
    else setTrackError(res.message);
  };

  const handleVerifyOtp = async () => {
    if (trackOtp.length !== 4) {
      setTrackError("Enter 4-digit code");
      return;
    }
    setTrackLoading(true);
    setTrackError("");
    const res = await AuthService.verifyOtp(trackPhone, trackOtp);
    setTrackLoading(false);
    if (res.success) {
      setIsLoggedIn(true);
      setTrackStep('history');
      const orders = await AuthService.getMyOrders();
      setUserOrders(orders);
    } else {
      setTrackError(res.message || "Verification failed");
    }
  };

  const updateQuantity = (productId: number, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === productId) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  // Added handleRemoveFromCart to fix the undefined function error in the cart drawer
  const handleRemoveFromCart = (productId: number) => {
    setCart(prev => prev.filter(item => item.id !== productId));
  };

  const handlePlaceOrder = async () => {
    if (!formData.customer_name.trim()) { setError("Name required"); return; }
    if (!/^(?:\+88|88)?(01[3-9]\d{8})$/.test(formData.phone)) { setError("Invalid phone"); return; }
    if (formData.address.length < 10) { setError("Address too short"); return; }

    setError(null);
    setIsSubmitting(true);
    const result = await ProductService.createOrder({
      ...formData,
      items: cart.map(item => ({ product_id: item.id, quantity: item.quantity }))
    });
    if (result.success && result.payment_url) {
      window.location.href = result.payment_url!;
    } else {
      setError(result.message);
      setIsSubmitting(false);
    }
  };

  const navigateToProduct = (product: Product) => {
    setCurrentRoute({ type: 'product', product });
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const navigateHome = () => {
    window.history.replaceState({}, '', '/');
    setCurrentRoute({ type: 'home' });
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  if (isAdmin) {
    return (
      <div className="min-h-screen bg-slate-50">
        <Navbar isAdmin={isAdmin} isLoggedIn={isLoggedIn} onAdminToggle={() => setIsAdmin(!isAdmin)} cartCount={cart.length} onCartClick={() => setIsCartOpen(true)} onTrackingClick={() => setCurrentRoute({ type: 'tracking' })} />
        <AdminPanel />
      </div>
    );
  }

  return (
    <div className="min-h-screen selection:bg-indigo-100 selection:text-indigo-900">
      <Navbar isAdmin={isAdmin} isLoggedIn={isLoggedIn} onAdminToggle={() => setIsAdmin(!isAdmin)} cartCount={cart.length} onCartClick={() => setIsCartOpen(true)} onTrackingClick={() => setCurrentRoute({ type: 'tracking' })} />

      <AnimatePresence mode="wait">
        {currentRoute.type === 'home' && (
          <motion.main key="home" initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}>
            {/* Hero Section */}
            <section className="relative overflow-hidden pt-16 pb-20 lg:pt-24 lg:pb-32">
              <div className="absolute top-0 left-1/2 -translate-x-1/2 w-full h-[600px] bg-gradient-to-b from-indigo-50/50 to-transparent -z-10 pointer-events-none" />
              <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 text-center">
