import { Product } from '../types';
import { PRODUCTS } from '../constants';

const API_BASE_URL = 'http://localhost:8000/api/v1';

export const ProductService = {
  async getAllProducts(params?: { category?: string; search?: string }): Promise<Product[]> {
    // Add realistic delay for skeleton loading demo
    await new Promise(resolve => setTimeout(resolve, 600));

    try {
      const url = new URL(`${API_BASE_URL}/products`);
      if (params?.category) url.searchParams.append('category', params.category);
      if (params?.search) url.searchParams.append('search', params.search);

      const response = await fetch(url.toString());
      if (!response.ok) throw new Error('Network response was not ok');
      const data = await response.json();
      return data.data; 
    } catch (error) {
      console.warn('ProductService: Falling back to local state.');
      let filtered = [...PRODUCTS];
      if (params?.category) {
        filtered = filtered.filter(p => p.category === params.category);
      }
      if (params?.search) {
        const query = params.search.toLowerCase();
        filtered = filtered.filter(p => 
          p.name.toLowerCase().includes(query) || 
          p.sku.toLowerCase().includes(query)
        );
      }
      return filtered;
    }
  },

  async getProductBySlug(slug: string): Promise<Product | null> {
    await new Promise(resolve => setTimeout(resolve, 400));
    try {
      const response = await fetch(`${API_BASE_URL}/products/${slug}`);
      if (!response.ok) return null;
      const data = await response.json();
      return data.data;
    } catch (error) {
      return PRODUCTS.find(p => p.slug === slug) || null;
    }
  },

  async createOrder(orderData: any): Promise<{ success: boolean; payment_url?: string; message: string }> {
    try {
      if (API_BASE_URL.includes('localhost')) {
         await new Promise(resolve => setTimeout(resolve, 1500));
         return {
            success: true,
            message: 'Order simulated successfully!',
            payment_url: 'https://sandbox.aamarpay.com/pay/vibe-demo-' + Math.floor(Math.random() * 1000000)
         };
      }

      const response = await fetch(`${API_BASE_URL}/orders`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Accept': 'application/json',
        },
        body: JSON.stringify(orderData),
      });

      const result = await response.json();

      if (!response.ok) {
        throw new Error(result.message || 'Failed to place order');
      }

      return result;
    } catch (error: any) {
      console.warn("Order submission simulation mode enabled.");
      await new Promise(resolve => setTimeout(resolve, 1500));
      return {
        success: true,
        message: 'Order simulation mode.',
        payment_url: 'https://sandbox.aamarpay.com/pay/vibe-demo-' + Math.floor(Math.random() * 1000000)
      };
    }
  }
};

import React, { useEffect, useState } from 'react';
