      return result;
    } catch (error: any) {
      // Simulation mode if API is unreachable
      if (API_BASE_URL.includes('localhost')) {
         await new Promise(resolve => setTimeout(resolve, 1500));
         return {
            success: true,
            message: 'Vibe Simulation Active.',
            payment_url: 'https://sandbox.aamarpay.com/pay/vibe-demo-' + Math.floor(Math.random() * 1000000)
         };
      }
      throw error;
    }
  }
};

