type Route = 
  | { type: 'home' } 
  | { type: 'product', product: Product }
  | { type: 'success', orderId: string }
  | { type: 'failed', reason: string }
  | { type: 'tracking' };

function useDebounce<T>(value: T, delay: number): T {
  const [debouncedValue, setDebouncedValue] = useState<T>(value);
  useEffect(() => {
    const handler = setTimeout(() => {
      setDebouncedValue(value);
    }, delay);
    return () => clearTimeout(handler);
  }, [value, delay]);
  return debouncedValue;
}

const App: React.FC = () => {
  const [isAdmin, setIsAdmin] = useState(false);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [isCheckoutOpen, setIsCheckoutOpen] = useState(false);
  const [isSearchOverlayOpen, setIsSearchOverlayOpen] = useState(false);
  const [selectedCategory, setSelectedCategory] = useState<string | null>(null);
  const [currentRoute, setCurrentRoute] = useState<Route>({ type: 'home' });
  const [isLoggedIn, setIsLoggedIn] = useState(AuthService.isLoggedIn());
  const [userOrders, setUserOrders] = useState<Order[]>([]);
  const productsSectionRef = useRef<HTMLDivElement>(null);

  const [searchQuery, setSearchQuery] = useState("");
  const debouncedSearch = useDebounce(searchQuery, 400);

  const [successOrder, setSuccessOrder] = useState<any>(null);
  const [successLoading, setSuccessLoading] = useState(false);

  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const orderId = params.get('order_id');
    const status = params.get('status');
    const reason = params.get('reason') || params.get('error');

    if (status === 'paid' && orderId) {
      setCurrentRoute({ type: 'success', orderId });
      setCart([]);
      fetchOrderDetails(orderId);
    } else if (reason) {
      setCurrentRoute({ type: 'failed', reason });
    }

    if (isLoggedIn) AuthService.getMyOrders().then(setUserOrders);
  }, [isLoggedIn]);

  const fetchOrderDetails = async (orderNumber: string) => {
    setSuccessLoading(true);
    try {
      const response = await fetch(`http://localhost:8000/api/v1/orders/${orderNumber}`);
      const result = await response.json();
      if (result.success) setSuccessOrder(result.data);
    } catch (err) {
      console.error("Failed to fetch order details", err);
    } finally {
      setSuccessLoading(false);
    }
  };

  const handleAddToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      return [...prev, { ...product, quantity: 1 }];
    });
    setIsCartOpen(true);
  };

  const handleUpdateCartQuantity = (id: number, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const handleRemoveFromCart = (id: number) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const handleCheckoutSubmit = async (formData: any) => {
    const orderData = {
      ...formData,
      items: cart.map(item => ({ product_id: item.id, quantity: item.quantity }))
    };

    const response = await ProductService.createOrder(orderData);
    if (response.success && response.payment_url) {
      window.location.href = response.payment_url;
    }
  };

  const navigateToProduct = (product: Product) => setCurrentRoute({ type: 'product', product });
  const navigateHome = () => {
    window.history.replaceState({}, '', '/');
    setCurrentRoute({ type: 'home' });
  };

  if (isAdmin) return <AdminPanel />;

  return (
    <div className="min-h-screen selection:bg-indigo-600 selection:text-white">
      <Navbar 
        isAdmin={isAdmin} 
        isLoggedIn={isLoggedIn} 
        onAdminToggle={() => setIsAdmin(true)} 
        cartCount={cart.length} 
        onCartClick={() => setIsCartOpen(true)} 
        onTrackingClick={() => setCurrentRoute({ type: 'tracking' })}
        onSearch={(query) => {
           setSearchQuery(query);
           if (query.length > 0) setIsSearchOverlayOpen(true);
        }}
      />

      <SearchOverlay 
        isOpen={isSearchOverlayOpen} 
        onClose={() => setIsSearchOverlayOpen(false)} 
        onSelectProduct={navigateToProduct}
      />

      <CartDrawer 
        isOpen={isCartOpen} 
        onClose={() => setIsCartOpen(false)} 
        items={cart} 
        onUpdateQuantity={handleUpdateCartQuantity}
        onRemove={handleRemoveFromCart}
        onCheckout={() => {
          setIsCartOpen(false);
          setIsCheckoutOpen(true);
        }}
      />

      <CheckoutModal 
        isOpen={isCheckoutOpen} 
        onClose={() => setIsCheckoutOpen(false)} 
        items={cart} 
