          >
            <div className="p-8 border-b border-slate-50 flex items-center justify-between">
              <span className="text-xs font-black uppercase tracking-widest">Cart ({items.length})</span>
              <button onClick={onClose} className="p-2 text-slate-400 hover:text-black transition-colors"><X size={18} /></button>
            </div>

            <div className="flex-1 overflow-y-auto p-8 space-y-10">
              {items.length === 0 ? (
                <div className="h-full flex flex-col items-center justify-center opacity-20">
                  <ShoppingBag size={48} className="mb-4" />
                  <p className="text-[10px] font-black uppercase tracking-widest">Empty</p>
                </div>
              ) : (
                items.map((item) => (
                  <div key={item.id} className="flex gap-4">
