            >
              <motion.img 
                src={product.image} 
                animate={{
                  scale: isZoomed ? 2 : 1,
                  x: isZoomed ? `${50 - mousePos.x}%` : 0,
                  y: isZoomed ? `${50 - mousePos.y}%` : 0,
                }}
                transition={{ type: 'tween', ease: 'easeOut', duration: 0.2 }}
                className="w-full h-full object-cover grayscale-[0.1] hover:grayscale-0 pointer-events-none" 
                alt={product.name} 
              />

              <div className="absolute bottom-6 left-6 pointer-events-none transition-opacity duration-300" style={{ opacity: isZoomed ? 0 : 1 }}>
