                  <div className="bg-white/90 backdrop-blur px-3 py-1.5 rounded-full border border-slate-100 flex items-center gap-1.5 shadow-sm">
                    <Zap size={10} fill="black" />
                    <span className="text-[8px] font-black uppercase tracking-widest text-black">Featured</span>
                  </div>
                )}
                <div className="bg-white/90 backdrop-blur px-3 py-1.5 rounded-full border border-slate-100 flex items-center gap-1.5 shadow-sm">
                  <Star size={10} fill="black" />
                  <span className="text-[8px] font-black uppercase tracking-widest text-black">4.9</span>
                </div>
              </div>
            </div>

            {/* Details Section */}
            <div className="flex-1 p-8 md:p-16 flex flex-col justify-center overflow-y-auto">
