                  <div className="flex items-center justify-between bg-slate-100 rounded-2xl px-6 py-4 w-full sm:w-40 border border-slate-200/50">
                    <button onClick={() => setQty(Math.max(1, qty - 1))} className="p-1 text-slate-400 hover:text-black transition-colors"><Minus size={18} /></button>
                    <span className="text-lg font-black tabular-nums">{qty}</span>
                    <button onClick={() => setQty(qty + 1)} className="p-1 text-slate-400 hover:text-black transition-colors"><Plus size={18} /></button>
