  onViewFullDetails: (p: Product) => void;
}

const ProductQuickView: React.FC<ProductQuickViewProps> = ({ product, onClose, onAddToCart, onViewFullDetails }) => {
  const [qty, setQty] = useState(1);
  const [isZoomed, setIsZoomed] = useState(false);
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });
  const containerRef = useRef<HTMLDivElement>(null);

  if (!product) return null;

  const handleMouseMove = (e: React.MouseEvent<HTMLDivElement>) => {
    if (!containerRef.current) return;
    const { left, top, width, height } = containerRef.current.getBoundingClientRect();
    const x = ((e.pageX - left - window.scrollX) / width) * 100;
    const y = ((e.pageY - top - window.scrollY) / height) * 100;
    setMousePos({ x, y });
  };

  return (
    <AnimatePresence>
      {product && (
        <div className="fixed inset-0 z-[400] flex items-center justify-center p-4 md:p-6">
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            onClick={onClose}
            className="absolute inset-0 bg-black/20 backdrop-blur-md"
          />
          <motion.div
            initial={{ scale: 0.95, opacity: 0, y: 10 }}
            animate={{ scale: 1, opacity: 1, y: 0 }}
            exit={{ scale: 0.95, opacity: 0, y: 10 }}
            transition={{ type: 'spring', damping: 30, stiffness: 400 }}
            className="relative w-full max-w-4xl bg-white rounded-[24px] shadow-2xl overflow-hidden flex flex-col md:flex-row max-h-[85vh]"
          >
            {/* Interactive Image Zoom Section */}
            <div 
              ref={containerRef}
              onMouseEnter={() => setIsZoomed(true)}
              onMouseLeave={() => setIsZoomed(false)}
              onMouseMove={handleMouseMove}
              className="w-full md:w-1/2 bg-slate-50 relative overflow-hidden h-72 md:h-auto cursor-zoom-in"
            >
              <motion.img 
                src={product.image} 
                animate={{
                  scale: isZoomed ? 2 : 1,
                  x: isZoomed ? `${50 - mousePos.x}%` : 0,
                  y: isZoomed ? `${50 - mousePos.y}%` : 0,
                }}
                transition={{ type: 'tween', ease: 'easeOut', duration: 0.2 }}
                className="w-full h-full object-cover grayscale-[0.1] hover:grayscale-0 pointer-events-none" 
                alt={product.name} 
              />

              <div className="absolute bottom-4 left-4 pointer-events-none transition-opacity duration-300" style={{ opacity: isZoomed ? 0 : 1 }}>
                 <div className="bg-black/50 backdrop-blur-md px-2 py-1 rounded-lg flex items-center gap-1.5 text-white border border-white/10">
                    <Search size={10} />
                    <span className="text-[8px] font-bold uppercase tracking-widest">Hover to Zoom</span>
                 </div>
              </div>

              <div className="absolute top-4 left-4 flex flex-col gap-1.5 pointer-events-none">
                {product.is_featured && (
                  <div className="bg-white/90 backdrop-blur px-2.5 py-1 rounded-full border border-slate-100 flex items-center gap-1 shadow-sm">
                    <Zap size={10} fill="black" />
                    <span className="text-[8px] font-black uppercase tracking-widest text-black">Featured</span>
                  </div>
                )}
              </div>
            </div>

            {/* Details Section */}
            <div className="flex-1 p-6 md:p-10 flex flex-col justify-center overflow-y-auto">
              <div className="mb-6">
                <span className="text-[9px] font-black text-indigo-600 uppercase tracking-[0.3em] mb-2 block">
                  {product.category}
                </span>
                <h2 className="text-2xl md:text-3xl font-black tracking-tighter text-slate-900 leading-none mb-3 uppercase">
                  {product.name}
                </h2>
                <div className="flex items-center gap-4 mb-4">
                  <span className="text-xl font-black text-black">৳{(product.sale_price || product.price).toLocaleString()}</span>
