                    <button onClick={() => setQty(Math.max(1, qty - 1))} className="p-1 text-slate-400 hover:text-black transition-colors"><Minus size={16} /></button>
                    <span className="text-base font-black tabular-nums">{qty}</span>
                    <button onClick={() => setQty(qty + 1)} className="p-1 text-slate-400 hover:text-black transition-colors"><Plus size={16} /></button>
                  </div>
                  <button 
                    onClick={() => {
                      onAddToCart(product, qty);
                      onClose();
                    }}
                    className="w-full bg-black text-white rounded-xl font-black py-4 hover:bg-slate-800 transition-all flex items-center justify-center gap-3 active:scale-[0.98] shadow-xl"
