import React, { useState, useEffect } from 'react';
import { ShoppingBag, Search, Zap, LayoutGrid, Menu } from 'lucide-react';

interface NavbarProps {
  onCartClick: () => void;
  onTrackingClick: () => void;
  cartCount: number;
  onAdminToggle: () => void;
  isAdmin: boolean;
  isLoggedIn: boolean;
  onSearch: (query: string) => void;
}

const Navbar: React.FC<NavbarProps> = ({ 
  onCartClick, 
  onTrackingClick, 
  cartCount, 
  onAdminToggle, 
  isAdmin, 
  isLoggedIn,
  onSearch 
}) => {
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  return (
    <nav className={`fixed top-0 w-full z-[100] transition-all duration-700 ${scrolled ? 'py-3 glass border-b border-white/10' : 'py-6 md:py-8'}`}>
      <div className="max-w-screen-2xl mx-auto px-8 lg:px-12 flex justify-between items-center">
        <div 
          className="flex items-center gap-2.5 cursor-pointer group" 
          onClick={() => window.location.href = '/'}
        >
          <div className="w-8 h-8 bg-black rounded-xl flex items-center justify-center text-white transition-transform group-hover:rotate-12" style={{ backgroundColor: 'var(--brand-text)', color: 'var(--brand-bg)' }}>
            <Zap size={16} fill="currentColor" />
          </div>
          <span className="text-xl font-black tracking-tighter uppercase">VIBE</span>
        </div>

        <div className="hidden md:flex items-center space-x-12">
          {['Archive', 'Curation', 'Manifesto'].map((item) => (
            <a key={item} href="#" className="text-[10px] font-black uppercase tracking-[0.3em] opacity-40 hover:opacity-100 transition-opacity">
              {item}
            </a>
          ))}
        </div>

        <div className="flex items-center gap-6">
          <button onClick={() => onSearch("")} className="opacity-40 hover:opacity-100 transition-opacity">
            <Search size={20} />
          </button>

          <button onClick={onCartClick} className="relative opacity-40 hover:opacity-100 transition-opacity">
            <ShoppingBag size={20} />
            {cartCount > 0 && (
              <span className="absolute -top-1.5 -right-1.5 bg-black text-white text-[8px] font-black w-4 h-4 rounded-full flex items-center justify-center" style={{ backgroundColor: 'var(--brand-accent)' }}>
                {cartCount}
              </span>
            )}
          </button>

          <button onClick={onAdminToggle} className="opacity-40 hover:opacity-100 transition-opacity">
            <LayoutGrid size={20} />
          </button>

          <button className="md:hidden opacity-40 hover:opacity-100 transition-opacity">
            <Menu size={20} />
          </button>
        </div>
      </div>
    </nav>
  );
};

