import React, { useState, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, ShoppingBag, Plus, Minus, Zap, ArrowRight, Search } from 'lucide-react';
import { Product } from '../types';

interface ProductQuickViewProps {
  product: Product | null;
  onClose: () => void;
  onAddToCart: (p: Product, qty: number) => void;
  onViewFullDetails: (p: Product) => void;
}

const ProductQuickView: React.FC<ProductQuickViewProps> = ({ product, onClose, onAddToCart, onViewFullDetails }) => {
  const [qty, setQty] = useState(1);
  const [isZoomed, setIsZoomed] = useState(false);
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });
  const containerRef = useRef<HTMLDivElement>(null);

  if (!product) return null;

  const handleMouseMove = (e: React.MouseEvent<HTMLDivElement>) => {
    if (!containerRef.current) return;
    const { left, top, width, height } = containerRef.current.getBoundingClientRect();
    const x = ((e.pageX - left - window.scrollX) / width) * 100;
    const y = ((e.pageY - top - window.scrollY) / height) * 100;
    setMousePos({ x, y });
  };

  return (
    <AnimatePresence>
      {product && (
        <div className="fixed inset-0 z-[400] flex items-center justify-center p-4 md:p-6">
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            onClick={onClose}
            className="absolute inset-0 bg-black/10 backdrop-blur-md"
          />
          <motion.div
            initial={{ scale: 0.95, opacity: 0, y: 10 }}
            animate={{ scale: 1, opacity: 1, y: 0 }}
            exit={{ scale: 0.95, opacity: 0, y: 10 }}
            transition={{ type: 'spring', damping: 30, stiffness: 400 }}
            className="relative w-full max-w-4xl bg-white rounded-[24px] shadow-2xl overflow-hidden flex flex-col md:flex-row max-h-[80vh]"
          >
            <div 
              ref={containerRef}
              onMouseEnter={() => setIsZoomed(true)}
              onMouseLeave={() => setIsZoomed(false)}
              onMouseMove={handleMouseMove}
              className="w-full md:w-1/2 bg-slate-50 relative overflow-hidden h-64 md:h-auto cursor-zoom-in"
            >
              <motion.img 
                src={product.image} 
                animate={{
                  scale: isZoomed ? 2 : 1,
                  x: isZoomed ? `${50 - mousePos.x}%` : 0,
                  y: isZoomed ? `${50 - mousePos.y}%` : 0,
                }}
                transition={{ type: 'tween', ease: 'easeOut', duration: 0.2 }}
                className="w-full h-full object-cover grayscale-[0.2] hover:grayscale-0 pointer-events-none" 
                alt={product.name} 
              />

              <div className="absolute bottom-4 left-4 pointer-events-none transition-opacity" style={{ opacity: isZoomed ? 0 : 0.6 }}>
                 <div className="bg-black/50 backdrop-blur-md px-2 py-1 rounded-lg flex items-center gap-1.5 text-white">
                    <Search size={10} />
                    <span className="text-[8px] font-bold uppercase tracking-widest">Zoom</span>
                 </div>
              </div>

              {product.is_featured && (
                <div className="absolute top-4 left-4 bg-white/90 backdrop-blur px-2.5 py-1 rounded-full border border-slate-100 flex items-center gap-1 shadow-sm pointer-events-none">
                  <Zap size={10} fill="black" />
                  <span className="text-[8px] font-black uppercase tracking-widest text-black">Featured</span>
                </div>
              )}
            </div>

            <div className="flex-1 p-8 md:p-12 flex flex-col justify-center overflow-y-auto">
              <div className="mb-8">
                <span className="text-[9px] font-black text-slate-400 uppercase tracking-[0.3em] mb-3 block">
                  {product.category}
                </span>
                <h2 className="text-3xl font-black tracking-tighter text-slate-900 leading-none mb-4 uppercase">
                  {product.name}
                </h2>
                <div className="flex items-center gap-4 mb-6">
                  <span className="text-2xl font-black text-black">৳{(product.sale_price || product.price).toLocaleString()}</span>
                  {product.sale_price && (
                    <span className="text-base text-slate-200 line-through font-bold">৳{product.price.toLocaleString()}</span>
                  )}
                </div>
                <p className="text-sm text-slate-400 font-medium leading-relaxed max-w-sm">
                  {product.description}
                </p>
              </div>

              <div className="space-y-6">
                <div className="flex flex-col sm:flex-row items-center gap-4">
                  <div className="flex items-center justify-between bg-slate-50 rounded-xl px-5 py-4 w-full sm:w-36 border border-slate-100">
                    <button onClick={() => setQty(Math.max(1, qty - 1))} className="p-1 text-slate-300 hover:text-black transition-colors"><Minus size={18} /></button>
                    <span className="text-lg font-black tabular-nums">{qty}</span>
                    <button onClick={() => setQty(qty + 1)} className="p-1 text-slate-300 hover:text-black transition-colors"><Plus size={18} /></button>
                  </div>
                  <button 
                    onClick={() => {
                      onAddToCart(product, qty);
                      onClose();
                    }}
                    className="w-full bg-black text-white rounded-xl font-black py-4 hover:bg-slate-800 transition-all flex items-center justify-center gap-3 active:scale-[0.98]"
                  >
                    <ShoppingBag size={20} />
                  </button>
                </div>

                <button 
                  onClick={() => {
                    onViewFullDetails(product);
                    onClose();
                  }}
                  className="w-full flex items-center justify-center gap-2 text-[9px] font-black uppercase tracking-[0.3em] text-slate-300 hover:text-black transition-colors pt-6 border-t border-slate-50"
                >
                  Manifesto <ArrowRight size={12} />
                </button>
              </div>
            </div>

            <button 
              onClick={onClose} 
              className="absolute top-6 right-6 p-2 text-slate-300 hover:text-black transition-all"
            >
              <X size={20} />
            </button>
          </motion.div>
        </div>
      )}
    </AnimatePresence>
  );
};

export default ProductQuickView;

