import React, { useState, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { ArrowUpRight } from 'lucide-react';
import Navbar from './components/Navbar';
import ProductGrid from './components/ProductGrid';
import AdminPanel from './components/AdminPanel';
import ProductDetailsPage from './components/ProductDetailsPage';
import SearchOverlay from './components/SearchOverlay';
import CartDrawer from './components/CartDrawer';
import CheckoutModal from './components/CheckoutModal';
import LogisticsTracker from './components/LogisticsTracker';
import WhatsAppButton from './components/WhatsAppButton';
import ProductQuickView from './components/ProductQuickView';
import { Product, CartItem } from './types';
import { CATEGORIES } from './constants';

type Route = 
  | { type: 'home' } 
  | { type: 'product', product: Product }
  | { type: 'success', orderId: string }
  | { type: 'tracking' };

const App: React.FC = () => {
  const [isAdmin, setIsAdmin] = useState(false);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [isCheckoutOpen, setIsCheckoutOpen] = useState(false);
  const [isSearchOpen, setIsSearchOpen] = useState(false);
  const [quickViewProduct, setQuickViewProduct] = useState<Product | null>(null);
  const [selectedCategory, setSelectedCategory] = useState<string | null>(null);
  const [currentRoute, setCurrentRoute] = useState<Route>({ type: 'home' });
  const productsSectionRef = useRef<HTMLDivElement>(null);

  // Calculate global totals for real-time Navbar update
  const cartTotal = cart.reduce((sum, item) => sum + (item.sale_price || item.price) * item.quantity, 0);
  const cartCount = cart.reduce((sum, item) => sum + item.quantity, 0);

  const handleAddToCart = (product: Product, quantity: number = 1) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + quantity } : item);
      return [...prev, { ...product, quantity }];
    });
    // Open cart drawer only if it was a deep view, or keep it closed for Chaldal-style fast adds
    // setIsCartOpen(true); 
  };

  const navigateToProduct = (product: Product) => {
    setCurrentRoute({ type: 'product', product });
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const navigateHome = () => setCurrentRoute({ type: 'home' });

  if (isAdmin) return <AdminPanel />;

  return (
    <div className="min-h-screen bg-white">
      <Navbar 
        isAdmin={isAdmin} 
        isLoggedIn={false} 
        onAdminToggle={() => setIsAdmin(true)} 
        cartCount={cartCount} 
        cartTotal={cartTotal}
        onCartClick={() => setIsCartOpen(true)} 
        onTrackingClick={() => setCurrentRoute({ type: 'tracking' })}
        onSearch={() => setIsSearchOpen(true)}
      />

      <SearchOverlay 
        isOpen={isSearchOpen} 
        onClose={() => setIsSearchOpen(false)} 
        onSelectProduct={navigateToProduct} 
      />

      <ProductQuickView 
        product={quickViewProduct}
        onClose={() => setQuickViewProduct(null)}
        onAddToCart={handleAddToCart}
        onViewFullDetails={navigateToProduct}
      />

      <CartDrawer 
        isOpen={isCartOpen} 
        onClose={() => setIsCartOpen(false)} 
        items={cart} 
        onUpdateQuantity={(id, delta) => {
          setCart(prev => prev.map(item => 
            item.id === id ? { ...item, quantity: Math.max(0, item.quantity + delta) } : item
          ).filter(item => item.quantity > 0));
        }} 
        onRemove={(id) => setCart(prev => prev.filter(item => item.id !== id))} 
        onCheckout={() => { setIsCartOpen(false); setIsCheckoutOpen(true); }} 
      />

      <CheckoutModal 
        isOpen={isCheckoutOpen} 
        onClose={() => setIsCheckoutOpen(false)} 
        items={cart} 
        onSubmit={async () => {}} 
      />

      <AnimatePresence mode="wait">
        {currentRoute.type === 'home' && (
          <motion.main 
            key="home" 
            initial={{ opacity: 0 }} 
            animate={{ opacity: 1 }} 
            exit={{ opacity: 0 }}
            className="relative"
          >
            <section className="h-[90vh] flex items-center relative overflow-hidden">
              <div className="absolute inset-0 z-0">
                <motion.div 
                  initial={{ scale: 1.1, opacity: 0 }}
                  animate={{ scale: 1, opacity: 0.1 }}
                  transition={{ duration: 1.5 }}
                  className="w-full h-full bg-[url('https://images.unsplash.com/photo-1550745165-9bc0b252726f?auto=format&fit=crop&q=80&w=2000')] bg-cover bg-center grayscale"
                />
              </div>

              <div className="max-w-7xl mx-auto px-12 w-full relative z-10">
                <motion.div 
                  initial={{ y: 30, opacity: 0 }} 
                  animate={{ y: 0, opacity: 1 }} 
                  transition={{ delay: 0.3, duration: 0.8 }}
                >
                  <h1 className="text-7xl md:text-9xl font-black tracking-tighter leading-[0.8] mb-8">
                    VIBE <br /> <span className="opacity-10">CORE.</span>
                  </h1>
                  <p className="text-lg md:text-xl font-medium max-w-lg mb-12 text-slate-400 leading-relaxed">
                    A curated archive of high-performance tools and luxury essentials for the modern pioneer.
                  </p>

                  <button 
                    onClick={() => productsSectionRef.current?.scrollIntoView({ behavior: 'smooth' })}
                    className="group flex items-center gap-4 bg-black text-white px-10 py-5 rounded-2xl text-[11px] font-black uppercase tracking-[0.3em] hover:scale-105 transition-all shadow-xl"
                  >
                    Enter Archive <ArrowUpRight size={16} />
                  </button>
                </motion.div>
              </div>
            </section>

            <section ref={productsSectionRef} className="py-20 px-12 max-w-screen-2xl mx-auto scroll-mt-20">
              <div className="flex flex-col md:flex-row justify-between items-end gap-8 mb-16">
                <h2 className="text-5xl font-black tracking-tighter uppercase leading-none">Archives</h2>
                <div className="flex gap-3">
                  {CATEGORIES.map(cat => (
                    <button 
                      key={cat.id}
                      onClick={() => setSelectedCategory(cat.slug === selectedCategory ? null : cat.slug)}
                      className={`px-6 py-3 rounded-xl text-[9px] font-black uppercase tracking-[0.2em] transition-all border ${selectedCategory === cat.slug ? 'bg-black text-white border-black' : 'bg-transparent text-slate-400 border-slate-100 hover:border-slate-300'}`}
                    >
                      {cat.name}
                    </button>
                  ))}
                </div>
              </div>
              <ProductGrid 
                category={selectedCategory} 
                search="" 
                onAddToCart={(p) => handleAddToCart(p, 1)} 
                onViewDetails={(p) => setQuickViewProduct(p)} 
              />
            </section>

            <section className="py-40 border-t border-slate-50">
               <div className="max-w-4xl mx-auto text-center px-12 relative z-10">
                  <h2 className="text-6xl font-black tracking-tighter mb-6 leading-none uppercase">Join the <br /> Circle.</h2>
                  <p className="text-lg font-medium mb-10 text-slate-400 max-w-lg mx-auto">Get exclusive access to pre-releases and ultra-limited physical archives.</p>
                  <div className="flex gap-3 max-w-md mx-auto">
                    <input 
                      type="email" 
                      placeholder="Email Identity" 
                      className="flex-1 bg-slate-50 border border-slate-100 rounded-xl px-6 py-4 text-xs font-bold outline-none focus:ring-1 focus:ring-black"
                    />
                    <button className="bg-black text-white px-8 py-4 rounded-xl font-black uppercase tracking-[0.2em] text-[10px]">Join</button>
                  </div>
               </div>
            </section>
          </motion.main>
        )}

        {currentRoute.type === 'product' && (
          <ProductDetailsPage product={currentRoute.product} onBack={navigateHome} onAddToCart={(p) => handleAddToCart(p, 1)} />
        )}

        {currentRoute.type === 'tracking' && (
          <LogisticsTracker onBack={navigateHome} />
        )}
      </AnimatePresence>

      <WhatsAppButton />
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, ShieldCheck, MapPin, Phone, User, Loader2, CreditCard, Plus, Minus, Trash2 } from 'lucide-react';
import { CartItem } from '../types';

interface CheckoutModalProps {
  isOpen: boolean;
  onClose: () => void;
  items: CartItem[];
  onUpdateQuantity: (id: number, delta: number) => void;
  onSubmit: (data: any) => Promise<void>;
}

const CheckoutModal: React.FC<CheckoutModalProps> = ({ isOpen, onClose, items, onUpdateQuantity, onSubmit }) => {
  const [loading, setLoading] = useState(false);
  const [formData, setFormData] = useState({
    customer_name: '',
    phone: '',
    address: '',
    area: 'Inside Dhaka'
  });

  const subtotal = items.reduce((sum, item) => sum + (item.sale_price || item.price) * item.quantity, 0);
  const shipping = formData.area === 'Inside Dhaka' ? 60 : 120;
  const total = subtotal + shipping;

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (items.length === 0) return;
    setLoading(true);
    try {
      await onSubmit(formData);
    } catch (err) {
      alert("Failed to process order. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <AnimatePresence>
      {isOpen && (
        <div className="fixed inset-0 z-[300] flex items-center justify-center p-6">
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            onClick={onClose}
            className="absolute inset-0 bg-slate-900/60 backdrop-blur-md"
          />
          <motion.div
            initial={{ scale: 0.9, opacity: 0, y: 20 }}
            animate={{ scale: 1, opacity: 1, y: 0 }}
            exit={{ scale: 0.9, opacity: 0, y: 20 }}
            className="relative w-full max-w-5xl bg-white rounded-[40px] shadow-2xl overflow-hidden flex flex-col md:flex-row"
          >
            {/* Form Section */}
            <div className="flex-1 p-10 md:p-16">
              <div className="flex items-center justify-between mb-12">
                <h2 className="text-3xl font-black tracking-tighter">Checkout</h2>
                <div className="flex items-center gap-2 text-emerald-500 bg-emerald-50 px-3 py-1 rounded-full">
                  <ShieldCheck size={14} />
                  <span className="text-[10px] font-black uppercase tracking-widest">Secured</span>
                </div>
              </div>

              <form onSubmit={handleSubmit} className="space-y-8">
                <div className="space-y-6">
                  <div className="relative group">
                    <User className="absolute left-6 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-indigo-600 transition-colors" size={18} />
                    <input
                      required
                      type="text"
                      placeholder="Full Name"
                      value={formData.customer_name}
                      onChange={(e) => setFormData({...formData, customer_name: e.target.value})}
                      className="w-full bg-slate-50 border-none rounded-2xl py-4 pl-14 pr-6 text-sm font-bold focus:ring-2 focus:ring-indigo-600/20 transition-all outline-none"
                    />
                  </div>

                  <div className="relative group">
                    <Phone className="absolute left-6 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-indigo-600 transition-colors" size={18} />
                    <input
                      required
                      type="tel"
                      placeholder="Phone Number (01xxxxxxxxx)"
                      value={formData.phone}
                      onChange={(e) => setFormData({...formData, phone: e.target.value})}
                      className="w-full bg-slate-50 border-none rounded-2xl py-4 pl-14 pr-6 text-sm font-bold focus:ring-2 focus:ring-indigo-600/20 transition-all outline-none"
                    />
                  </div>

                  <div className="grid grid-cols-2 gap-4">
                    {['Inside Dhaka', 'Outside Dhaka'].map(area => (
                      <button
                        key={area}
                        type="button"
                        onClick={() => setFormData({...formData, area})}
                        className={`py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${formData.area === area ? 'bg-indigo-600 text-white shadow-lg' : 'bg-slate-50 text-slate-400 hover:bg-slate-100'}`}
                      >
                        {area}
                      </button>
                    ))}
                  </div>

                  <div className="relative group">
                    <MapPin className="absolute left-6 top-5 text-slate-300 group-focus-within:text-indigo-600 transition-colors" size={18} />
                    <textarea
                      required
                      rows={3}
                      placeholder="Full Delivery Address"
                      value={formData.address}
                      onChange={(e) => setFormData({...formData, address: e.target.value})}
                      className="w-full bg-slate-50 border-none rounded-2xl py-4 pl-14 pr-6 text-sm font-bold focus:ring-2 focus:ring-indigo-600/20 transition-all outline-none resize-none"
                    />
                  </div>
                </div>

                <button
                  disabled={loading || items.length === 0}
                  className="w-full bg-slate-900 text-white py-6 rounded-2xl font-black text-[11px] uppercase tracking-[0.4em] hover:bg-indigo-600 transition-all shadow-xl shadow-slate-200 disabled:opacity-50 flex items-center justify-center gap-4"
                >
                  {loading ? (
                    <>
                      <Loader2 className="animate-spin" size={20} /> Initializing Gateway
                    </>
                  ) : items.length === 0 ? (
                    'Cart Empty'
                  ) : (
                    <>
                      Pay ৳{total.toLocaleString()} <CreditCard size={18} />
                    </>
                  )}
                </button>
              </form>
            </div>

