type Route = 
  | { type: 'home' } 
  | { type: 'product', product: Product }
  | { type: 'success', orderId: string }
  | { type: 'tracking' };

const App: React.FC = () => {
  const [isAdmin, setIsAdmin] = useState(false);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [isCheckoutOpen, setIsCheckoutOpen] = useState(false);
  const [isSearchOpen, setIsSearchOpen] = useState(false);
  const [quickViewProduct, setQuickViewProduct] = useState<Product | null>(null);
  const [selectedCategory, setSelectedCategory] = useState<string | null>(null);
  const [currentRoute, setCurrentRoute] = useState<Route>({ type: 'home' });
  const [toastProduct, setToastProduct] = useState<Product | null>(null);
  const [showToast, setShowToast] = useState(false);
  const productsSectionRef = useRef<HTMLDivElement>(null);

  const cartTotal = cart.reduce((sum, item) => sum + (item.sale_price || item.price) * item.quantity, 0);
  const cartCount = cart.reduce((sum, item) => sum + item.quantity, 0);

  const handleUpdateQuantity = (id: number, delta: number) => {
    setCart(prev => prev.map(item => 
      item.id === id ? { ...item, quantity: Math.max(0, item.quantity + delta) } : item
    ).filter(item => item.quantity > 0));
  };

  const handleAddToCart = (product: Product, quantity: number = 1) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + quantity } : item);
      return [...prev, { ...product, quantity }];
    });

    // Show Toast
    setToastProduct(product);
    setShowToast(true);
    setTimeout(() => setShowToast(false), 3000);
  };

  const navigateToProduct = (product: Product) => {
    setCurrentRoute({ type: 'product', product });
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const navigateHome = () => setCurrentRoute({ type: 'home' });

  if (isAdmin) return <AdminPanel />;

  return (
    <div className="min-h-screen bg-white">
      <CustomCursor />
      <PremiumToast product={toastProduct} isVisible={showToast} />

      <Navbar 
        isAdmin={isAdmin} 
        isLoggedIn={false} 
        onAdminToggle={() => setIsAdmin(true)} 
        cartCount={cartCount} 
        cartTotal={cartTotal}
        onCartClick={() => setIsCartOpen(true)} 
        onTrackingClick={() => setCurrentRoute({ type: 'tracking' })}
        onSearch={() => setIsSearchOpen(true)}
      />

      <SearchOverlay 
        isOpen={isSearchOpen} 
        onClose={() => setIsSearchOpen(false)} 
        onSelectProduct={navigateToProduct} 
      />

      <ProductQuickView 
        product={quickViewProduct}
        onClose={() => setQuickViewProduct(null)}
        onAddToCart={handleAddToCart}
        onViewFullDetails={navigateToProduct}
      />

      <CartDrawer 
        isOpen={isCartOpen} 
        onClose={() => setIsCartOpen(false)} 
        items={cart} 
        onUpdateQuantity={handleUpdateQuantity} 
        onRemove={(id) => handleUpdateQuantity(id, -cart.find(i => i.id === id)!.quantity)} 
        onCheckout={() => { setIsCartOpen(false); setIsCheckoutOpen(true); }} 
      />

      <CheckoutModal 
        isOpen={isCheckoutOpen} 
        onClose={() => setIsCheckoutOpen(false)} 
        items={cart} 
        onUpdateQuantity={handleUpdateQuantity}
        onSubmit={async () => {}} 
      />

      <AnimatePresence mode="wait">
        {currentRoute.type === 'home' && (
          <motion.main 
            key="home" 
            initial={{ opacity: 0 }} 
            animate={{ opacity: 1 }} 
            exit={{ opacity: 0 }}
            className="relative"
          >
            {/* Ultra-Luxury Hero */}
            <section className="h-screen flex items-center relative overflow-hidden bg-white">
              <div className="absolute inset-0 z-0">
                <motion.div 
                  initial={{ scale: 1.2, opacity: 0 }}
                  animate={{ scale: 1, opacity: 0.15 }}
                  transition={{ duration: 2, ease: "easeOut" }}
                  className="w-full h-full bg-[url('https://images.unsplash.com/photo-1550745165-9bc0b252726f?auto=format&fit=crop&q=80&w=2000')] bg-cover bg-center grayscale"
                />
                <div className="absolute inset-0 bg-gradient-to-b from-transparent via-white/50 to-white" />
              </div>

              <div className="max-w-screen-2xl mx-auto px-12 md:px-24 w-full relative z-10">
                <motion.div 
                  initial={{ y: 60, opacity: 0 }} 
                  animate={{ y: 0, opacity: 1 }} 
                  transition={{ delay: 0.4, duration: 1, ease: [0.22, 1, 0.36, 1] }}
                >
                  <span className="text-[10px] font-black uppercase tracking-[0.5em] text-indigo-600 block mb-8">Spring // Summer 2024</span>
                  <h1 className="text-8xl md:text-[12rem] font-black tracking-tighter leading-[0.75] mb-12 uppercase">
                    The Elite <br /> <span className="text-slate-200">Archive.</span>
                  </h1>

                  <div className="flex flex-col md:flex-row items-end justify-between gap-12 mt-20">
                    <p className="text-xl md:text-2xl font-medium max-w-xl text-slate-400 leading-relaxed tracking-tight">
                      Curated performance essentials engineered for the modern pioneer. Discover physical archives that define high-vibe living.
                    </p>

                    <button 
                      onClick={() => productsSectionRef.current?.scrollIntoView({ behavior: 'smooth' })}
                      className="group relative bg-black text-white px-12 py-7 rounded-full text-[11px] font-black uppercase tracking-[0.4em] overflow-hidden"
                    >
                      <span className="relative z-10 flex items-center gap-4">Enter Curation <ArrowUpRight size={18} /></span>
                      <motion.div 
                        className="absolute inset-0 bg-indigo-600 translate-y-full group-hover:translate-y-0 transition-transform duration-500" 
                      />
                    </button>
                  </div>
                </motion.div>
              </div>
            </section>

            {/* Editorial Showcase Section */}
            <section className="py-40 bg-[#fcfcfc]">
              <div className="max-w-screen-2xl mx-auto px-12 md:px-24 grid grid-cols-1 lg:grid-cols-12 gap-12 items-center">
                <div className="lg:col-span-5">
                   <motion.div 
                    initial={{ opacity: 0, x: -50 }}
                    whileInView={{ opacity: 1, x: 0 }}
                    viewport={{ once: true }}
                    className="space-y-10"
                   >
                     <h3 className="text-4xl md:text-6xl font-black tracking-tighter uppercase leading-none">High <br /> Performance <br /> Optics.</h3>
                     <p className="text-slate-400 font-medium leading-relaxed max-w-sm">
                       Our technical archives represent the pinnacle of digital craftsmanship. Each item is authenticated for the Vibe ecosystem.
                     </p>
                     <button className="text-[10px] font-black uppercase tracking-[0.3em] flex items-center gap-3 group border-b border-black pb-2">
                       Explore Tech Archive <Plus size={14} className="group-hover:rotate-90 transition-transform" />
                     </button>
                   </motion.div>
                </div>
                <div className="lg:col-span-7 grid grid-cols-2 gap-8">
                  <motion.div 
                    initial={{ opacity: 0, y: 100 }}
                    whileInView={{ opacity: 1, y: 0 }}
                    viewport={{ once: true }}
                    transition={{ delay: 0.2 }}
                    className="aspect-[3/4] rounded-[3rem] overflow-hidden bg-slate-100 group cursor-pointer"
                  >
                    <img src={PRODUCTS[0].image} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-1000" />
                  </motion.div>
                  <motion.div 
                    initial={{ opacity: 0, y: 100 }}
                    whileInView={{ opacity: 1, y: 0 }}
                    viewport={{ once: true }}
                    transition={{ delay: 0.4 }}
                    className="aspect-[3/4] rounded-[3rem] overflow-hidden bg-slate-100 mt-20 group cursor-pointer"
                  >
                    <img src={PRODUCTS[2].image} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-1000" />
                  </motion.div>
                </div>
              </div>
            </section>

            {/* Refined Catalog */}
            <section ref={productsSectionRef} className="py-40 px-12 md:px-24 max-w-screen-2xl mx-auto scroll-mt-20">
              <div className="flex flex-col md:flex-row justify-between items-end gap-12 mb-24">
                <div className="space-y-4">
                  <span className="text-[10px] font-black uppercase tracking-[0.4em] text-indigo-600">The Curation</span>
                  <h2 className="text-7xl font-black tracking-tighter uppercase leading-none">Archives</h2>
                </div>
                <div className="flex flex-wrap gap-4">
                  <button 
                    onClick={() => setSelectedCategory(null)}
