import React, { useEffect } from 'react';
import { motion, useSpring, useMotionValue, AnimatePresence } from 'framer-motion';
import { Product } from '../types';
import { Zap } from 'lucide-react';

interface ProductHoverCardProps {
  product: Product | null;
}

const ProductHoverCard: React.FC<ProductHoverCardProps> = ({ product }) => {
  const mouseX = useMotionValue(-100);
  const mouseY = useMotionValue(-100);

  const springConfig = { damping: 25, stiffness: 400 };
  const x = useSpring(mouseX, springConfig);
  const y = useSpring(mouseY, springConfig);

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      mouseX.set(e.clientX + 20); // Offset from cursor
      mouseY.set(e.clientY + 20);
    };

    window.addEventListener('mousemove', handleMouseMove);
    return () => window.removeEventListener('mousemove', handleMouseMove);
  }, [mouseX, mouseY]);

  return (
    <AnimatePresence>
      {product && (
        <motion.div
          className="fixed top-0 left-0 z-[1000] pointer-events-none hidden lg:block"
          style={{ x, y }}
          initial={{ opacity: 0, scale: 0.8, y: 10 }}
          animate={{ opacity: 1, scale: 1, y: 0 }}
          exit={{ opacity: 0, scale: 0.8, y: 10 }}
        >
          <div className="bg-white/80 backdrop-blur-xl border border-white/20 shadow-[0_30px_60px_-15px_rgba(0,0,0,0.15)] rounded-3xl p-5 min-w-[220px] overflow-hidden">
            <div className="flex gap-4 items-center">
              <div className="w-14 h-14 rounded-xl overflow-hidden bg-slate-100 flex-shrink-0">
                <img src={product.image} className="w-full h-full object-cover" alt="" />
              </div>
              <div className="flex-1 min-w-0">
                <p className="text-[8px] font-black uppercase tracking-[0.3em] text-indigo-600 mb-1 flex items-center gap-1">
                  {product.is_featured && <Zap size={8} fill="currentColor" />}
                  {product.category}
                </p>
                <h4 className="text-[11px] font-black uppercase text-slate-900 truncate mb-1">{product.name}</h4>
                <p className="text-[10px] font-black text-slate-400">৳{(product.sale_price || product.price).toLocaleString()}</p>
              </div>
            </div>

            <div className="mt-4 pt-3 border-t border-slate-100 flex items-center justify-between">
              <span className="text-[7px] font-black uppercase tracking-widest text-slate-300">Click to Inspect</span>
              <div className="w-1 h-1 rounded-full bg-indigo-500 animate-pulse" />
            </div>
          </div>
        </motion.div>
      )}
    </AnimatePresence>
  );
};

export default ProductHoverCard;

import React from 'react';
import { Plus, Zap, Eye } from 'lucide-react';
import { Product } from '../types';
import { motion } from 'framer-motion';

interface ProductCardProps {
  product: Product;
  onAddToCart: (p: Product) => void;
  onViewDetails: (p: Product) => void;
  onHover?: (p: Product | null) => void;
}

const ProductCard: React.FC<ProductCardProps> = ({ product, onAddToCart, onViewDetails, onHover }) => {
  return (
    <motion.div 
      initial={{ opacity: 0, y: 20 }}
      whileInView={{ opacity: 1, y: 0 }}
      viewport={{ once: true }}
      className="group"
      onMouseEnter={() => onHover?.(product)}
      onMouseLeave={() => onHover?.(null)}
    >
      <div 
        className="relative aspect-[4/5] overflow-hidden bg-[var(--brand-card)] rounded-[2rem] cursor-pointer border border-[var(--brand-border)] transition-all duration-700"
        onClick={() => onViewDetails(product)}
      >
        <motion.img 
          src={product.image} 
          alt={product.name} 
          className="w-full h-full object-cover transition-transform duration-1000 group-hover:scale-110 grayscale-[0.2] group-hover:grayscale-0"
        />

        {product.is_featured && (
          <div className="absolute top-4 left-4 glass px-3 py-1.5 rounded-full border border-white/20 shadow-lg">
             <span className="text-[8px] font-black uppercase tracking-widest flex items-center gap-1.5">
               <Zap size={10} fill="currentColor" style={{ color: 'var(--brand-accent)' }} /> 
               Featured
             </span>
          </div>
        )}

        {/* Hover Gradient Overlay */}
        <div className="absolute inset-0 bg-gradient-to-t from-black/30 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-500" />

        <div className="absolute bottom-6 left-0 right-0 flex justify-center items-center gap-3 translate-y-6 opacity-0 group-hover:translate-y-0 group-hover:opacity-100 transition-all duration-500">
          <button 
            onClick={(e) => { e.stopPropagation(); onAddToCart(product); }}
            className="w-12 h-12 bg-white text-black rounded-xl font-black shadow-2xl hover:scale-110 active:scale-95 transition-all flex items-center justify-center border border-slate-100"
            title="Add to Archive"
          >
            <Plus size={18} strokeWidth={3} />
          </button>
          <button 
            onClick={(e) => { e.stopPropagation(); onViewDetails(product); }}
            className="w-12 h-12 bg-white/20 backdrop-blur-md rounded-xl text-white border border-white/20 hover:scale-110 active:scale-95 transition-all flex items-center justify-center"
            title="Quick View"
          >
             <Eye size={18} strokeWidth={2.5} />
          </button>
        </div>
      </div>

      <div className="mt-4 px-1">
        <div className="flex justify-between items-start gap-2">
          <div>
            <h3 className="text-sm font-black tracking-tight leading-tight uppercase mb-1">{product.name}</h3>
            <p className="text-[9px] font-black uppercase tracking-[0.2em] opacity-40">{product.category}</p>
          </div>
          <span className="text-sm font-black tracking-tighter" style={{ color: 'var(--brand-accent)' }}>
            ৳{(product.sale_price || product.price).toLocaleString()}
          </span>
        </div>
      </div>
    </motion.div>
  );
};

export default ProductCard;

import React, { useEffect, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { SearchX, Loader2 } from 'lucide-react';
import ProductCard from './ProductCard';
import { Product } from '../types';
import { ProductService } from '../services/productService';

interface ProductGridProps {
  category: string | null;
  search: string;
  onAddToCart: (p: Product) => void;
  onViewDetails: (p: Product) => void;
  onProductHover?: (p: Product | null) => void;
}

const ProductSkeleton = () => (
  <div className="bg-white rounded-2xl border border-slate-100 overflow-hidden shadow-sm">
    <div className="aspect-square shimmer bg-slate-100" />
    <div className="p-4 space-y-2">
      <div className="h-2 w-1/4 shimmer bg-slate-100 rounded" />
      <div className="h-4 w-3/4 shimmer bg-slate-100 rounded" />
      <div className="h-4 w-1/2 shimmer bg-slate-100 rounded" />
    </div>
  </div>
);

const ProductGrid: React.FC<ProductGridProps> = ({ category, search, onAddToCart, onViewDetails, onProductHover }) => {
  const [products, setProducts] = useState<Product[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchProducts = async () => {
      setLoading(true);
      const data = await ProductService.getAllProducts({
        category: category || undefined,
        search: search || undefined
      });
      setProducts(data);
      setLoading(false);
    };

    fetchProducts();
  }, [category, search]);

  if (loading) {
    return (
      <div className="space-y-8">
        {search && (
          <div className="flex items-center gap-2 text-slate-500 font-medium animate-pulse">
            <Loader2 className="animate-spin" size={18} />
            <span>Searching for "{search}"...</span>
          </div>
        )}
        <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 sm:gap-6 lg:gap-8">
          {[...Array(8)].map((_, i) => (
            <ProductSkeleton key={i} />
          ))}
        </div>
      </div>
    );
  }

  return (
    <AnimatePresence mode="wait">
      <motion.div 
        key={`${category || 'all'}-${search}`}
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        exit={{ opacity: 0, scale: 0.95 }}
        transition={{ duration: 0.4, ease: [0.23, 1, 0.32, 1] }}
        className="grid grid-cols-2 lg:grid-cols-4 gap-4 sm:gap-6 lg:gap-8"
      >
        {products.length > 0 ? (
          products.map((product, index) => (
            <motion.div
              key={product.id}
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: index * 0.05 }}
            >
              <ProductCard 
                product={product} 
                onAddToCart={onAddToCart} 
                onViewDetails={onViewDetails}
                onHover={onProductHover}
              />
            </motion.div>
          ))
        ) : (
          <div className="col-span-full py-32 flex flex-col items-center justify-center text-center">
            <motion.div 
              initial={{ scale: 0.8, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              className="w-24 h-24 bg-slate-50 text-slate-300 rounded-full flex items-center justify-center mb-6"
            >
              <SearchX size={48} />
            </motion.div>
            <h3 className="text-2xl font-bold text-slate-800 mb-2">No vibes matched your search</h3>
            <p className="text-slate-500 max-w-sm mx-auto">
              We couldn't find anything for "{search}". Maybe try searching for something else or browse our categories.
            </p>
          </div>
        )}
      </motion.div>
    </AnimatePresence>
  );
};

export default ProductGrid;

