interface NavbarProps {
  onCartClick: () => void;
  onTrackingClick: () => void;
  cartCount: number;
  cartTotal: number;
  onAdminToggle: () => void;
  isAdmin: boolean;
  isLoggedIn: boolean;
  onSearch: (query: string) => void;
  onMenuClick: () => void;
}

const Navbar: React.FC<NavbarProps> = ({ 
  onCartClick, 
  onTrackingClick, 
