                  transition={{ delay: 0.2, duration: 0.8, ease: [0.22, 1, 0.36, 1] }}
                >
                  <span className="text-xs font-bold uppercase tracking-[0.3em] text-indigo-600 block mb-6">Spring // Summer 2024</span>
                  <h1 className="text-6xl md:text-8xl font-bold tracking-tight leading-[1.1] mb-8 uppercase">
                    The Elite <br /> <span className="text-slate-300">Archive.</span>
