                           <div className="flex items-center gap-2">
                              <span className={`w-2 h-2 rounded-full ${order.shippingStatus === ShippingStatus.DELIVERED ? 'bg-emerald-500' : order.shippingStatus === ShippingStatus.PENDING ? 'bg-amber-400' : 'bg-indigo-500 animate-pulse'}`} />
                              <p className="text-xs font-bold text-slate-900 uppercase tracking-tight">{order.shippingStatus}</p>
                           </div>
                        </td>
                        <td className="px-6 py-4 text-right">
