          <div>
            <h1 className="text-xl font-black tracking-tight text-slate-900 uppercase">
              {activeTab === 'dash' ? 'Performance Insights' : activeTab === 'orders' ? 'Order Command Center' : 'Archive Registry'}
            </h1>
          </div>

          <div className="flex items-center gap-4">
             {selectedOrders.length > 0 && (
               <motion.div initial={{ opacity: 0, y: -20 }} animate={{ opacity: 1, y: 0 }} className="flex items-center gap-3 bg-indigo-50 border border-indigo-100 px-4 py-2 rounded-2xl">
                 <span className="text-[10px] font-black text-indigo-600 uppercase tracking-widest">{selectedOrders.length} Selected</span>
                 <div className="w-px h-4 bg-indigo-200" />
                 <button onClick={() => updateStatus(selectedOrders, ShippingStatus.PROCESSING)} className="text-[10px] font-black text-indigo-600 uppercase hover:underline">Confirm All</button>
