import React, { useState, useMemo } from 'react';
import { 
  LayoutDashboard, ShoppingCart, Package, Settings, Plus, 
  Truck, Activity, MessageSquare, Download, CheckCircle2, 
  AlertCircle, ChevronRight, MoreVertical, Trash2, Search,
  Filter, ExternalLink, RefreshCw, Send, FileJson
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer
} from 'recharts';
import { MOCK_ORDERS, PRODUCTS, CATEGORIES } from '../constants';
import { Order, Product, ShippingStatus, PaymentStatus } from '../types';

const AdminPanel: React.FC = () => {
  const [activeTab, setActiveTab] = useState('orders');
  const [orders, setOrders] = useState<Order[]>(MOCK_ORDERS);
  const [products, setProducts] = useState<Product[]>(PRODUCTS);
  const [selectedOrders, setSelectedOrders] = useState<number[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('all');

  // --- BUSINESS LOGIC: ANALYTICS CALCULATIONS (THE 80% OUTCOME) ---
  const analytics = useMemo(() => {
    const paidOrders = orders.filter(o => o.paymentStatus === PaymentStatus.PAID);
    const gmv = paidOrders.reduce((acc, curr) => acc + curr.totalAmount, 0);
    const aov = paidOrders.length > 0 ? gmv / paidOrders.length : 0;
    const lowStock = products.filter(p => p.stock < 10).length;

    // Generating chart data from real-ish order volume
    const dailyRevenue = orders.reduce((acc: any, order) => {
      const date = order.createdAt.split(' ')[0];
      acc[date] = (acc[date] || 0) + order.totalAmount;
      return acc;
    }, {});

    const revenueChart = Object.keys(dailyRevenue).map(date => ({
      name: date,
      revenue: dailyRevenue[date]
    })).slice(-7);

    // Fallback if no order history
    if (revenueChart.length < 2) {
      revenueChart.push(
        { name: 'Mon', revenue: 42000 },
        { name: 'Tue', revenue: 38000 },
        { name: 'Wed', revenue: 51000 },
        { name: 'Thu', revenue: 45000 },
        { name: 'Fri', revenue: 62000 }
      );
    }

    return { gmv, aov, ordersCount: orders.length, lowStock, revenueChart };
  }, [orders, products]);

  // --- BUSINESS LOGIC: ORDER ACTIONS ---
  const handleUpdateOrderStatus = (orderIds: number[], newStatus: ShippingStatus) => {
    setOrders(prev => prev.map(order => 
      orderIds.includes(order.id) ? { ...order, shippingStatus: newStatus } : order
    ));
    setSelectedOrders([]);
    // Notification: console.log(`Triggering SMS for ${orderIds.length} orders: Status set to ${newStatus}`);
  };

  const getWhatsAppLink = (order: Order) => {
    let message = "";
    if (order.shippingStatus === ShippingStatus.PENDING) {
      message = `Salam ${order.customerName}, we received your order #${order.orderNumber}. Please confirm your address: ${order.address}. Total: ৳${order.totalAmount}. - Vibe-Store`;
    } else if (order.shippingStatus === ShippingStatus.SHIPPED) {
      message = `Great news ${order.customerName}, your order #${order.orderNumber} is on the way! Tracker: ${order.orderNumber}. - Vibe-Store`;
    } else {
      message = `Salam ${order.customerName}, regarding your order #${order.orderNumber}...`;
    }
    return `https://wa.me/${order.phone}?text=${encodeURIComponent(message)}`;
  };

  const handleExportForCourier = () => {
    const exportData = orders
      .filter(o => selectedOrders.length === 0 || selectedOrders.includes(o.id))
      .map(o => ({
        "Recipient Name": o.customerName,
        "Recipient Phone": o.phone,
        "Recipient Address": o.address,
        "COD Amount": o.paymentStatus === PaymentStatus.PAID ? 0 : o.totalAmount,
        "Note": `Order #${o.orderNumber}`
      }));

    const blob = new Blob([JSON.stringify(exportData, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `VIBE_COURIER_EXPORT_${new Date().toISOString().slice(0,10)}.json`;
    a.click();
  };

  const filteredOrders = orders.filter(o => {
    const matchesSearch = o.customerName.toLowerCase().includes(searchQuery.toLowerCase()) || o.orderNumber.includes(searchQuery);
    const matchesStatus = statusFilter === 'all' || o.shippingStatus === statusFilter;
    return matchesSearch && matchesStatus;
  });

  const toggleOrderSelection = (id: number) => {
    setSelectedOrders(prev => prev.includes(id) ? prev.filter(oid => oid !== id) : [...prev, id]);
  };

  return (
    <div className="min-h-screen bg-[#fafafa] flex font-['Inter']">
      {/* Sidebar */}
      <aside className="w-64 bg-white border-r border-slate-200 hidden lg:flex flex-col sticky top-0 h-screen">
        <div className="p-6">
          <div className="flex items-center gap-3 mb-10 px-2">
            <div className="w-9 h-9 bg-indigo-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-indigo-100">
              <Activity size={18} />
            </div>
            <span className="text-xl font-bold tracking-tight text-slate-900 uppercase">Vibe<span className="text-indigo-600">.</span>Core</span>
          </div>

          <nav className="space-y-1">
            {[
              { id: 'dash', icon: LayoutDashboard, label: 'Performance' },
              { id: 'orders', icon: ShoppingCart, label: 'Operations' },
              { id: 'products', icon: Package, label: 'Inventory' },
              { id: 'settings', icon: Settings, label: 'System' }
            ].map((item) => (
              <button 
                key={item.id}
                onClick={() => setActiveTab(item.id)}
                className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl text-[13px] font-semibold tracking-tight transition-all ${activeTab === item.id ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}
              >
                <item.icon size={16} /> {item.label}
              </button>
            ))}
          </nav>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 min-w-0 flex flex-col">
        <header className="h-20 bg-white border-b border-slate-200 px-10 flex items-center justify-between sticky top-0 z-50">
          <h1 className="text-lg font-bold tracking-tight text-slate-900 uppercase">
            {activeTab === 'dash' ? 'Performance Hub' : activeTab === 'orders' ? 'Control Tower' : 'Warehouse'}
          </h1>

          <div className="flex items-center gap-4">
             {selectedOrders.length > 0 && (
               <motion.div initial={{ opacity: 0, x: 20 }} animate={{ opacity: 1, x: 0 }} className="flex items-center gap-2 bg-slate-50 border border-slate-200 px-4 py-1.5 rounded-xl">
                 <span className="text-[10px] font-bold text-slate-500 uppercase">{selectedOrders.length} SELECTED</span>
                 <div className="w-px h-4 bg-slate-200 mx-2" />
                 <button 
                   onClick={() => handleUpdateOrderStatus(selectedOrders, ShippingStatus.PROCESSING)}
                   className="text-[10px] font-bold text-indigo-600 uppercase hover:underline"
                 >
                   Confirm
                 </button>
                 <button 
                   onClick={handleExportForCourier}
                   className="text-[10px] font-bold text-slate-900 uppercase hover:underline"
                 >
                   Export
                 </button>
               </motion.div>
             )}
             <button className="flex items-center gap-2 bg-slate-900 text-white px-6 py-2.5 rounded-xl text-[11px] font-bold uppercase tracking-widest hover:bg-indigo-600 transition-all">
                <Plus size={16} /> New Entry
             </button>
          </div>
        </header>

        <div className="p-10 max-w-[1400px] w-full mx-auto space-y-10">
          {activeTab === 'dash' && (
            <div className="space-y-10">
               <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-4 gap-6">
                 {[
                   { label: 'Total Revenue', value: `৳${analytics.gmv.toLocaleString()}`, icon: Activity },
                   { label: 'Live Orders', value: analytics.ordersCount, icon: ShoppingCart },
                   { label: 'Avg Basket', value: `৳${Math.round(analytics.aov).toLocaleString()}`, icon: TrendingUp },
                   { label: 'Low Stock', value: analytics.lowStock, icon: AlertCircle, color: analytics.lowStock > 0 ? 'text-amber-500' : 'text-slate-900' }
                 ].map((stat, i) => (
                   <div key={i} className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
                      <div className="flex justify-between items-start mb-4">
                        <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{stat.label}</p>
                        <stat.icon size={14} className="text-slate-300" />
                      </div>
                      <p className={`text-2xl font-bold tracking-tight ${stat.color || 'text-slate-900'}`}>{stat.value}</p>
                   </div>
                 ))}
               </div>

               <div className="bg-white p-8 rounded-3xl border border-slate-200 shadow-sm">
                 <div className="flex items-center justify-between mb-8">
                   <h3 className="text-sm font-bold uppercase tracking-widest text-slate-400">Revenue Flow (Last 7 Days)</h3>
                   <div className="flex items-center gap-2 text-[10px] font-bold text-emerald-500 uppercase">
                     <TrendingUp size={12} /> +12% Growth
                   </div>
                 </div>
                 <div className="h-[300px] w-full">
                   <ResponsiveContainer width="100%" height="100%">
                     <AreaChart data={analytics.revenueChart}>
                       <defs>
                         <linearGradient id="colorRev" x1="0" y1="0" x2="0" y2="1">
                           <stop offset="5%" stopColor="#4f46e5" stopOpacity={0.1}/>
                           <stop offset="95%" stopColor="#4f46e5" stopOpacity={0}/>
                         </linearGradient>
                       </defs>
                       <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fontSize: 10, fontWeight: 700}} />
                       <YAxis axisLine={false} tickLine={false} tick={{fontSize: 10, fontWeight: 700}} />
                       <Tooltip 
                         contentStyle={{borderRadius: '16px', border: 'none', boxShadow: '0 10px 30px rgba(0,0,0,0.05)', fontSize: '11px', fontWeight: 800}} 
                       />
                       <Area type="monotone" dataKey="revenue" stroke="#4f46e5" strokeWidth={3} fillOpacity={1} fill="url(#colorRev)" />
                     </AreaChart>
                   </ResponsiveContainer>
                 </div>
               </div>
            </div>
          )}

          {activeTab === 'orders' && (
            <div className="space-y-6">
              <div className="flex flex-col md:flex-row gap-4 justify-between items-center bg-white p-6 rounded-3xl border border-slate-200">
                <div className="relative w-full md:w-96">
                  <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={16} />
                  <input 
                    type="text" 
                    placeholder="Search by name or order ID..." 
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    className="w-full bg-slate-50 rounded-xl py-2.5 pl-12 pr-4 text-xs font-semibold outline-none focus:ring-1 focus:ring-indigo-600/20 transition-all"
                  />
                </div>
                <div className="flex gap-2 w-full md:w-auto">
                  {['all', 'pending', 'processing', 'shipped', 'delivered'].map(status => (
                    <button 
                      key={status}
                      onClick={() => setStatusFilter(status)}
                      className={`px-4 py-2 rounded-xl text-[9px] font-bold uppercase tracking-widest transition-all ${statusFilter === status ? 'bg-black text-white' : 'bg-slate-50 text-slate-400 hover:bg-slate-100'}`}
