                            onChange={() => toggleOrderSelection(order.id)}
                            className="rounded border-slate-200 text-indigo-600" 
                          />
                        </td>
                        <td className="px-6 py-4">
                          <p className="text-xs font-bold text-slate-900">#{order.orderNumber}</p>
                          <p className="text-[9px] font-medium text-slate-400 uppercase mt-0.5">{order.createdAt}</p>
                        </td>
                        <td className="px-6 py-4">
                          <p className="text-xs font-bold text-slate-900">{order.customerName}</p>
                          <p className="text-[9px] font-medium text-slate-400 uppercase mt-0.5">{order.area}</p>
                        </td>
                        <td className="px-6 py-4">
                          <p className="text-xs font-bold text-slate-900">৳{order.totalAmount.toLocaleString()}</p>
                          <span className={`text-[8px] font-bold uppercase tracking-widest ${order.paymentStatus === PaymentStatus.PAID ? 'text-emerald-500' : 'text-amber-500'}`}>
                            {order.paymentStatus}
                          </span>
                        </td>
                        <td className="px-6 py-4">
                           <div className="flex items-center gap-2">
                              <span className={`w-2 h-2 rounded-full ${order.shippingStatus === ShippingStatus.DELIVERED ? 'bg-emerald-500' : order.shippingStatus === ShippingStatus.PENDING ? 'bg-amber-400' : 'bg-indigo-500 animate-pulse'}`} />
                              <p className="text-xs font-bold text-slate-900 uppercase tracking-tight">{order.shippingStatus}</p>
                           </div>
                        </td>
                        <td className="px-6 py-4 text-right">
                          <div className="flex justify-end gap-2">
                            <a 
                              href={getWhatsAppLink(order)} 
                              target="_blank" 
