                              title="Send WhatsApp Update"
                            >
                              <MessageSquare size={14} />
                            </a>
                            <button 
                              className="p-2 bg-slate-100 text-slate-400 rounded-lg hover:bg-indigo-600 hover:text-white transition-all"
                              onClick={() => handleUpdateOrderStatus([order.id], ShippingStatus.SHIPPED)}
                            >
                              <Truck size={14} />
                            </button>
                          </div>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {activeTab === 'products' && (
             <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-4 gap-6">
               {products.map(p => {
                 const isLow = p.stock < 10;
                 return (
                  <div key={p.id} className="bg-white p-5 rounded-3xl border border-slate-200 shadow-sm hover:shadow-md transition-all group">
                     <div className="aspect-square rounded-2xl overflow-hidden bg-slate-50 mb-5 relative">
                        <img src={p.image} className="w-full h-full object-cover transition-all" />
