                           <div className="text-right">
                              <p className={`text-[9px] font-bold uppercase tracking-widest ${isLow ? 'text-amber-500' : 'text-slate-400'}`}>
                                {p.stock} units
                              </p>
                              <p className="text-[7px] font-bold text-slate-300 uppercase">Archive ID: {p.sku}</p>
                           </div>
                        </div>
                     </div>
                  </div>
                 );
               })}
             </div>
          )}
        </div>
      </main>
    </div>
  );
};

