                  <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={16} />
                  <input 
                    type="text" 
                    placeholder="Search by name or order ID..." 
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    className="w-full bg-slate-50 rounded-xl py-2.5 pl-12 pr-4 text-xs font-semibold outline-none focus:ring-1 focus:ring-indigo-600/20 transition-all"
                  />
