                      <th className="px-6 py-4 text-[10px] font-bold text-slate-400 uppercase tracking-widest">Customer</th>
                      <th className="px-6 py-4 text-[10px] font-bold text-slate-400 uppercase tracking-widest">Payment</th>
                      <th className="px-6 py-4 text-[10px] font-bold text-slate-400 uppercase tracking-widest">Logistics</th>
                      <th className="px-6 py-4 text-[10px] font-bold text-slate-400 uppercase tracking-widest text-right">Actions</th>
                    </tr>
                  </thead>
                  <tbody>
                    {filteredOrders.map(order => (
                      <tr key={order.id} className="border-b border-slate-50 hover:bg-slate-50/50 transition-colors">
                        <td className="px-6 py-4">
                          <input 
                            type="checkbox" 
                            checked={selectedOrders.includes(order.id)}
                            onChange={() => toggleOrderSelection(order.id)}
                            className="rounded border-slate-200 text-indigo-600" 
                          />
                        </td>
                        <td className="px-6 py-4">
                          <p className="text-xs font-bold text-slate-900">#{order.orderNumber}</p>
                          <p className="text-[9px] font-medium text-slate-400 uppercase mt-0.5">{order.createdAt}</p>
                        </td>
                        <td className="px-6 py-4">
                          <p className="text-xs font-bold text-slate-900">{order.customerName}</p>
                          <p className="text-[9px] font-medium text-slate-400 uppercase mt-0.5">{order.area}</p>
                        </td>
                        <td className="px-6 py-4">
                          <p className="text-xs font-bold text-slate-900">৳{order.totalAmount.toLocaleString()}</p>
                          <span className={`text-[8px] font-bold uppercase tracking-widest ${order.paymentStatus === PaymentStatus.PAID ? 'text-emerald-500' : 'text-amber-500'}`}>
                            {order.paymentStatus}
                          </span>
                        </td>
                        <td className="px-6 py-4">
                           <div className="flex items-center gap-2">
                              <span className={`w-2 h-2 rounded-full ${order.shippingStatus === ShippingStatus.DELIVERED ? 'bg-emerald-500' : order.shippingStatus === ShippingStatus.PENDING ? 'bg-amber-400' : 'bg-indigo-500 animate-pulse'}`} />
                              <p className="text-xs font-bold text-slate-900 uppercase tracking-tight">{order.shippingStatus}</p>
                           </div>
                        </td>
                        <td className="px-6 py-4 text-right">
                          <div className="flex justify-end gap-2">
                            <a 
                              href={getWhatsAppLink(order)} 
                              target="_blank" 
                              rel="noopener noreferrer"
                              className="p-2 bg-emerald-50 text-emerald-600 rounded-lg hover:bg-emerald-600 hover:text-white transition-all"
                              title="Send WhatsApp Update"
                            >
                              <MessageSquare size={14} />
                            </a>
                            <button 
                              className="p-2 bg-slate-100 text-slate-400 rounded-lg hover:bg-indigo-600 hover:text-white transition-all"
                              onClick={() => handleUpdateOrderStatus([order.id], ShippingStatus.SHIPPED)}
                            >
                              <Truck size={14} />
                            </button>
                          </div>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {activeTab === 'products' && (
             <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-4 gap-6">
               {products.map(p => {
                 const isLow = p.stock < 10;
                 return (
                  <div key={p.id} className="bg-white p-5 rounded-3xl border border-slate-200 shadow-sm hover:shadow-md transition-all group">
                     <div className="aspect-square rounded-2xl overflow-hidden bg-slate-50 mb-5 relative">
                        <img src={p.image} className="w-full h-full object-cover transition-all" />
                        {isLow && (
                          <div className="absolute top-3 left-3 bg-amber-500 text-white text-[8px] font-black uppercase px-2 py-1 rounded-lg shadow-lg">
                            Low Stock
                          </div>
                        )}
                     </div>
                     <div>
                        <p className="text-[8px] font-bold text-indigo-600 uppercase tracking-widest mb-1">{p.category}</p>
                        <h4 className="font-bold text-slate-900 tracking-tight leading-tight uppercase text-sm">{p.name}</h4>
                        <div className="flex items-center justify-between mt-5 pt-4 border-t border-slate-50">
                           <p className="text-base font-bold text-slate-900">৳{p.sale_price || p.price}</p>
                           <div className="text-right">
                              <p className={`text-[9px] font-bold uppercase tracking-widest ${isLow ? 'text-amber-500' : 'text-slate-400'}`}>
                                {p.stock} units
                              </p>
                              <p className="text-[7px] font-bold text-slate-300 uppercase">Archive ID: {p.sku}</p>
                           </div>
                        </div>
                     </div>
                  </div>
                 );
               })}
             </div>
          )}
        </div>
      </main>
    </div>
  );
};

