import React, { useState, useMemo } from 'react';
import { 
  LayoutDashboard, ShoppingCart, Package, Settings, Plus, 
  Truck, Activity, MessageSquare, Download, CheckCircle2, 
  AlertCircle, ChevronRight, MoreVertical, Trash2, Search,
  Filter, ExternalLink, RefreshCw, Send, FileJson, TrendingUp,
  CreditCard, ShieldAlert, Phone, MapPin, X, Info, User
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer
} from 'recharts';
import { MOCK_ORDERS, PRODUCTS } from '../constants';
import { Order, Product, ShippingStatus, PaymentStatus } from '../types';

const AdminPanel: React.FC = () => {
  const [activeTab, setActiveTab] = useState('orders');
  const [orders, setOrders] = useState<Order[]>(MOCK_ORDERS);
  const [products] = useState<Product[]>(PRODUCTS);
  const [selectedOrders, setSelectedOrders] = useState<number[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('all');
  const [selectedOrderDetails, setSelectedOrderDetails] = useState<Order | null>(null);
  const [smsLog, setSmsLog] = useState<{msg: string, time: string}[]>([]);

  // --- BUSINESS LOGIC: FRAUD DETECTION (80% OUTCOME) ---
  const getCustomerRisk = (phone: string) => {
    const customerOrders = orders.filter(o => o.phone === phone);
    const cancellations = customerOrders.filter(o => o.shippingStatus === ShippingStatus.CANCELLED).length;
    if (cancellations >= 2) return { level: 'HIGH', color: 'text-rose-500', bg: 'bg-rose-50' };
    if (cancellations === 1) return { level: 'MEDIUM', color: 'text-amber-500', bg: 'bg-amber-50' };
    return { level: 'SAFE', color: 'text-emerald-500', bg: 'bg-emerald-50' };
  };

  // --- BUSINESS LOGIC: ANALYTICS (REAL-TIME GMV & KPI) ---
  const analytics = useMemo(() => {
    const paidOrders = orders.filter(o => o.paymentStatus === PaymentStatus.PAID);
    const gmv = paidOrders.reduce((acc, curr) => acc + curr.totalAmount, 0);
    const aov = paidOrders.length > 0 ? gmv / paidOrders.length : 0;
    const fraudThreats = orders.filter(o => getCustomerRisk(o.phone).level === 'HIGH').length;

    const dailyRevenue = orders.reduce((acc: any, order) => {
      const date = order.createdAt.split(' ')[0];
      acc[date] = (acc[date] || 0) + (order.paymentStatus === PaymentStatus.PAID ? order.totalAmount : 0);
      return acc;
    }, {});

    const revenueChart = Object.keys(dailyRevenue).map(date => ({
      name: date,
      revenue: dailyRevenue[date]
    })).slice(-7);

    // Fallback if no order history
    if (revenueChart.length < 2) {
      revenueChart.push(
        { name: 'Mon', revenue: 42000 },
        { name: 'Tue', revenue: 38000 },
        { name: 'Wed', revenue: 51000 },
        { name: 'Thu', revenue: 45000 },
        { name: 'Fri', revenue: 62000 }
      );
    }

    return { gmv, aov, ordersCount: orders.length, fraudThreats, revenueChart };
  }, [orders]);

  // --- BUSINESS LOGIC: AUTOMATED SMS SIMULATION ---
  const triggerSms = (order: Order, type: 'CONFIRMED' | 'SHIPPED') => {
    const msg = type === 'CONFIRMED' 
      ? `Salam ${order.customerName}, your Order #${order.orderNumber} is CONFIRMED. Total: ৳${order.totalAmount}. - VibeStore`
      : `Salam ${order.customerName}, Order #${order.orderNumber} is SHIPPED via Pathao. Tracker: ${order.orderNumber}. - VibeStore`;

    setSmsLog(prev => [{ msg, time: new Date().toLocaleTimeString() }, ...prev]);
  };

  // --- BUSINESS LOGIC: STATUS MANAGEMENT ---
  const updateStatus = (orderIds: number[], status: ShippingStatus) => {
    setOrders(prev => prev.map(o => {
      if (orderIds.includes(o.id)) {
        const updated = { ...o, shippingStatus: status };
        if (status === ShippingStatus.PROCESSING) triggerSms(updated, 'CONFIRMED');
        if (status === ShippingStatus.SHIPPED) triggerSms(updated, 'SHIPPED');
        return updated;
      }
      return o;
    }));
    setSelectedOrders([]);
  };

  const handleUpdatePayment = (orderId: number, trxId: string) => {
    setOrders(prev => prev.map(o => 
      o.id === orderId ? { ...o, paymentStatus: PaymentStatus.PAID, address: o.address + ` (Trx: ${trxId})` } : o
    ));
    setSelectedOrderDetails(null);
  };

  // --- COURIER EXPORT (JSON FORMAT FOR BULK UPLOAD) ---
  const exportOrders = () => {
    const targets = orders.filter(o => selectedOrders.includes(o.id) || selectedOrders.length === 0);
    const data = targets.map(o => ({
      recipient_name: o.customerName,
      recipient_phone: o.phone,
      recipient_address: o.address,
      destination: o.area,
      cod_amount: o.paymentStatus === PaymentStatus.PAID ? 0 : o.totalAmount,
      item_quantity: 1,
      order_id: o.orderNumber
    }));

    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `VIBE_COURIER_EXPORT_${new Date().getTime()}.json`;
    a.click();
  };

  const filteredOrders = orders.filter(o => {
    const query = searchQuery.toLowerCase();
    const matchSearch = o.customerName.toLowerCase().includes(query) || o.orderNumber.toLowerCase().includes(query) || o.phone.includes(query);
    const matchStatus = statusFilter === 'all' || o.shippingStatus === statusFilter;
    return matchSearch && matchStatus;
  });

  return (
    <div className="min-h-screen bg-[#fafafa] flex font-['Inter']">
      {/* Admin Sidebar */}
      <aside className="w-64 bg-white border-r border-slate-200 hidden lg:flex flex-col sticky top-0 h-screen">
        <div className="p-8">
          <div className="flex items-center gap-3 mb-12">
            <div className="w-10 h-10 bg-indigo-600 rounded-2xl flex items-center justify-center text-white shadow-xl shadow-indigo-100">
              <Activity size={20} />
            </div>
            <span className="text-xl font-black tracking-tighter text-slate-900 uppercase">VIBE<span className="text-indigo-600">.</span>OS</span>
          </div>

          <nav className="space-y-1">
            {[
              { id: 'dash', icon: LayoutDashboard, label: 'Analytics' },
              { id: 'orders', icon: ShoppingCart, label: 'Control Tower' },
              { id: 'products', icon: Package, label: 'Inventory' },
              { id: 'settings', icon: Settings, label: 'Automation' }
            ].map((item) => (
              <button 
                key={item.id}
                onClick={() => setActiveTab(item.id)}
                className={`w-full flex items-center gap-3 px-5 py-3.5 rounded-2xl text-[13px] font-bold tracking-tight transition-all ${activeTab === item.id ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-100' : 'text-slate-400 hover:bg-slate-50'}`}
              >
                <item.icon size={18} strokeWidth={2.5} /> {item.label}
              </button>
            ))}
          </nav>
        </div>

        <div className="mt-auto p-8">
           <div className="bg-slate-50 rounded-2xl p-4 border border-slate-100">
              <p className="text-[10px] font-black uppercase text-slate-400 tracking-widest mb-2">System Status</p>
              <div className="flex items-center gap-2">
                 <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse" />
                 <span className="text-xs font-bold text-slate-900">API Operational</span>
              </div>
           </div>
        </div>
      </aside>

      {/* Main Command View */}
      <main className="flex-1 min-w-0 flex flex-col">
        <header className="h-24 bg-white/80 backdrop-blur-md border-b border-slate-200 px-10 flex items-center justify-between sticky top-0 z-[100]">
          <div>
            <h1 className="text-xl font-black tracking-tight text-slate-900 uppercase">
              {activeTab === 'dash' ? 'Performance Insights' : activeTab === 'orders' ? 'Order Command Center' : 'Inventory Manager'}
