import React, { useState, useMemo } from 'react';
import { 
  LayoutDashboard, ShoppingCart, Package, Settings, Plus, 
  Truck, Activity, MessageSquare, Download, CheckCircle2, 
  AlertCircle, ChevronRight, MoreVertical, Trash2, Search,
  Filter, ExternalLink, RefreshCw, Send, FileJson, TrendingUp,
  CreditCard, ShieldAlert, Phone, MapPin, X, Info, User, FileSpreadsheet
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer
} from 'recharts';
import { MOCK_ORDERS, PRODUCTS } from '../constants';
import { Order, Product, ShippingStatus, PaymentStatus } from '../types';

const AdminPanel: React.FC = () => {
  const [activeTab, setActiveTab] = useState('orders');
  const [orders, setOrders] = useState<Order[]>(MOCK_ORDERS);
  const [products] = useState<Product[]>(PRODUCTS);
  const [selectedOrders, setSelectedOrders] = useState<number[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('all');
  const [selectedOrderDetails, setSelectedOrderDetails] = useState<Order | null>(null);
  const [smsLog, setSmsLog] = useState<{msg: string, time: string}[]>([]);
  const [exportMenuOpen, setExportMenuOpen] = useState(false);

  // --- BUSINESS LOGIC: FRAUD DETECTION & RISK SCORING ---
  const getCustomerRisk = (phone: string) => {
    const customerOrders = orders.filter(o => o.phone === phone);
    const cancellations = customerOrders.filter(o => o.shippingStatus === ShippingStatus.CANCELLED).length;
    if (cancellations >= 2) return { level: 'HIGH', color: 'text-rose-500', bg: 'bg-rose-50', label: 'Blacklisted' };
    if (cancellations === 1) return { level: 'MEDIUM', color: 'text-amber-500', bg: 'bg-amber-50', label: 'Caution' };
    return { level: 'SAFE', color: 'text-emerald-500', bg: 'bg-emerald-50', label: 'Trusted' };
  };

  // --- BUSINESS LOGIC: LOGISTICS MANIFEST EXPORT (THE PAINKILLER) ---
  const exportForCourier = (courier: 'PATHAO' | 'STEADFAST' | 'GENERAL') => {
    const targets = orders.filter(o => selectedOrders.includes(o.id) || (selectedOrders.length === 0 && o.shippingStatus === ShippingStatus.PROCESSING));

    if (targets.length === 0) {
      alert("No processing orders selected for export.");
      return;
    }

    let exportData: any[] = [];

    if (courier === 'PATHAO') {
      exportData = targets.map(o => ({
        recipient_name: o.customerName,
        recipient_phone: o.phone.replace(/^88/, ''), // Pathao usually wants 11 digits
        recipient_address: o.address,
        recipient_city: o.area.includes('Dhaka') ? 'Dhaka' : 'Outside Dhaka',
        amount_to_collect: o.paymentStatus === PaymentStatus.PAID ? 0 : o.totalAmount,
        item_quantity: 1,
        merchant_order_id: o.orderNumber,
        item_description: 'Vibe Archive Product'
      }));
    } else if (courier === 'STEADFAST') {
      exportData = targets.map(o => ({
        invoice: o.orderNumber,
        recipient_name: o.customerName,
        recipient_phone: o.phone,
        recipient_address: o.address,
        cod_amount: o.paymentStatus === PaymentStatus.PAID ? 0 : o.totalAmount,
        note: `VIBE Order #${o.orderNumber}`
      }));
    } else {
      exportData = targets.map(o => ({
        "Order #": o.orderNumber,
        "Customer": o.customerName,
        "Contact": o.phone,
        "Address": o.address,
        "Area": o.area,
        "COD": o.paymentStatus === PaymentStatus.PAID ? 0 : o.totalAmount,
        "Status": o.shippingStatus
      }));
    }

    const blob = new Blob([JSON.stringify(exportData, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `VIBE_${courier}_MANIFEST_${new Date().toISOString().slice(0,10)}.json`;
    a.click();
    setExportMenuOpen(false);
  };

  // --- BUSINESS LOGIC: CONTEXT-AWARE CRM MESSAGING ---
  const getCRMContext = (order: Order) => {
    const cleanPhone = order.phone.replace(/^0/, '880');
    const baseUrl = `https://wa.me/${cleanPhone}?text=`;
    let message = "";

    switch (order.shippingStatus) {
      case ShippingStatus.PENDING:
        message = `Salam ${order.customerName}, we received your order #${order.orderNumber}. Please confirm your address: "${order.address}". Total: ৳${order.totalAmount}. Reply 'YES' to confirm. - VibeStore BD`;
        break;
      case ShippingStatus.PROCESSING:
        message = `Salam ${order.customerName}! Your order #${order.orderNumber} is confirmed and packing. We'll update you soon with tracking info. - VibeStore BD`;
        break;
      case ShippingStatus.SHIPPED:
        message = `Great news ${order.customerName}! Your order #${order.orderNumber} is on its way. Track it here: https://vibe-store.bd/track/${order.orderNumber}. - VibeStore BD`;
        break;
      default:
        message = `Salam ${order.customerName}, regarding your order #${order.orderNumber}...`;
    }

    return { 
      link: baseUrl + encodeURIComponent(message),
      preview: message
    };
  };

  // --- BUSINESS LOGIC: ANALYTICS & DASHBOARD ---
  const analytics = useMemo(() => {
    const paidOrders = orders.filter(o => o.paymentStatus === PaymentStatus.PAID);
    const gmv = paidOrders.reduce((acc, curr) => acc + curr.totalAmount, 0);
    const aov = paidOrders.length > 0 ? gmv / paidOrders.length : 0;
    const fraudThreats = orders.filter(o => getCustomerRisk(o.phone).level === 'HIGH').length;

    const dailyRevenue = orders.reduce((acc: any, order) => {
      const date = order.createdAt.split(' ')[0];
