                         className={`py-6 rounded-3xl text-[11px] font-black uppercase tracking-[0.2em] text-white transition-all hover:scale-[1.02] active:scale-95 shadow-xl flex items-center justify-center gap-3 ${action.color}`}
                       >
                         <action.icon size={16} strokeWidth={3} /> {action.label}
                       </button>
                     ))}
                  </div>
               </div>
            </motion.div>
          </div>
        )}
      </AnimatePresence>
    </div>
  );
};

