    if (cancellations >= 2) return { level: 'HIGH', color: 'text-rose-500', bg: 'bg-rose-50', label: 'Blacklisted' };
    if (cancellations === 1) return { level: 'MEDIUM', color: 'text-amber-500', bg: 'bg-amber-50', label: 'Caution' };
    return { level: 'SAFE', color: 'text-emerald-500', bg: 'bg-emerald-50', label: 'Trusted' };
