import React, { useState, useMemo } from 'react';
import { 
  LayoutDashboard, ShoppingCart, Package, Settings, Plus, 
  Truck, Activity, MessageSquare, Download, CheckCircle2, 
  AlertCircle, ChevronRight, MoreVertical, Trash2, Search,
  Filter, ExternalLink, RefreshCw, Send, FileJson, TrendingUp,
  CreditCard, ShieldAlert, Phone, MapPin, X, Info, User, FileSpreadsheet,
  CheckCircle, Ban
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer
} from 'recharts';
import { MOCK_ORDERS, PRODUCTS } from '../constants';
import { Order, Product, ShippingStatus, PaymentStatus } from '../types';

const AdminPanel: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dash');
  const [orders, setOrders] = useState<Order[]>(MOCK_ORDERS);
  const [selectedOrders, setSelectedOrders] = useState<number[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('all');
  const [selectedOrderDetails, setSelectedOrderDetails] = useState<Order | null>(null);
  const [smsLog, setSmsLog] = useState<{msg: string, time: string}[]>([]);
  const [isExporting, setIsExporting] = useState(false);

  // --- BUSINESS LOGIC: FRAUD DETECTION ---
  const getCustomerRisk = (phone: string) => {
    // In a real app, this would query a global blacklist or the full order history
    const customerOrders = orders.filter(o => o.phone === phone);
    const cancellations = customerOrders.filter(o => o.shippingStatus === ShippingStatus.CANCELLED).length;

    if (cancellations >= 2) return { level: 'HIGH', color: 'text-rose-500', bg: 'bg-rose-50', label: 'Blacklisted', risk: 95 };
    if (cancellations === 1) return { level: 'MEDIUM', color: 'text-amber-500', bg: 'bg-amber-50', label: 'Caution', risk: 45 };
    return { level: 'SAFE', color: 'text-emerald-500', bg: 'bg-emerald-50', label: 'Trusted', risk: 5 };
  };

  // --- BUSINESS LOGIC: ONE-CLICK WHATSAPP CRM ---
  const handleWhatsAppCRM = (order: Order) => {
    const cleanPhone = order.phone.replace(/^0/, '880');
    let message = "";

    // Contextual templates based on status
    if (order.shippingStatus === ShippingStatus.PENDING) {
      message = `Salam ${order.customerName}, we received your order #${order.orderNumber}. Please confirm your address: "${order.address}". Total: ৳${order.totalAmount}. Reply 'YES' to confirm. - VibeStore BD`;
    } else if (order.shippingStatus === ShippingStatus.SHIPPED) {
      message = `Salam ${order.customerName}! Your order #${order.orderNumber} is on its way. Track it here: https://vibe.bd/track/${order.orderNumber}. - VibeStore BD`;
    } else {
      message = `Salam ${order.customerName}, regarding your order #${order.orderNumber}...`;
    }

    const url = `https://wa.me/${cleanPhone}?text=${encodeURIComponent(message)}`;
    window.open(url, '_blank');

    // Log as a "CRM Action"
    setSmsLog(prev => [{ msg: `[WA CRM] Sent confirmation request to ${order.customerName}`, time: new Date().toLocaleTimeString() }, ...prev]);
  };

  // --- BUSINESS LOGIC: LOGISTICS EXPORT ---
  const handleManifestExport = (courier: 'PATHAO' | 'STEADFAST') => {
