    let manifestData = [];
    if (courier === 'PATHAO') {
      manifestData = targets.map(o => ({
        recipient_name: o.customerName,
        recipient_phone: o.phone.replace(/^88/, ''),
        recipient_address: o.address,
        cod_amount: o.paymentStatus === PaymentStatus.PAID ? 0 : o.totalAmount,
        item_type: 'Parcel',
        merchant_order_id: o.orderNumber
      }));
    } else {
      manifestData = targets.map(o => ({
        invoice: o.orderNumber,
        recipient_name: o.customerName,
        recipient_phone: o.phone,
        recipient_address: o.address,
        cod_amount: o.paymentStatus === PaymentStatus.PAID ? 0 : o.totalAmount
      }));
    }

    const blob = new Blob([JSON.stringify(manifestData, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `VIBE_${courier}_MANIFEST_${new Date().toISOString().split('T')[0]}.json`;
    link.click();

    setSmsLog(prev => [{ msg: `[EXPORT] Generated ${courier} manifest for ${targets.length} orders`, time: new Date().toLocaleTimeString() }, ...prev]);
