import { Product } from '../types';
import { PRODUCTS } from '../constants';

const API_BASE_URL = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:8000/api/v1';

export const ProductService = {
  async getAllProducts(params?: { category?: string; search?: string }): Promise<Product[]> {
    try {
      const url = new URL(`${API_BASE_URL}/products`);
      if (params?.category) url.searchParams.append('category', params.category);
      if (params?.search) url.searchParams.append('search', params.search);

      const response = await fetch(url.toString());
      if (!response.ok) throw new Error('Network response was not ok');
      const data = await response.json();
      return data.data; 
    } catch (error) {
      console.warn('Vibe-Store: Falling back to Archive state.');
      let filtered = [...PRODUCTS];
      if (params?.category) filtered = filtered.filter(p => p.category === params.category);
      if (params?.search) {
        const query = params.search.toLowerCase();
        filtered = filtered.filter(p => p.name.toLowerCase().includes(query) || p.sku.toLowerCase().includes(query));
      }
      return filtered;
    }
  },

  async searchProducts(query: string): Promise<Product[]> {
    if (!query || query.length < 2) return [];
    try {
      const response = await fetch(`${API_BASE_URL}/search?q=${encodeURIComponent(query)}`);
      if (!response.ok) throw new Error('Search failed');
      const data = await response.json();
      return data.data;
    } catch (error) {
      const q = query.toLowerCase();
      return PRODUCTS.filter(p => p.name.toLowerCase().includes(q) || p.sku.toLowerCase().includes(q)).slice(0, 5);
    }
  },

  async createOrder(orderData: any): Promise<{ success: boolean; payment_url?: string; message: string; order_number?: string }> {
    try {
      const response = await fetch(`${API_BASE_URL}/orders`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Accept': 'application/json',
        },
        body: JSON.stringify(orderData),
      });

      const result = await response.json();
      if (!response.ok) throw new Error(result.message || 'Failed to place order');
      return result;
    } catch (error: any) {
      // For local testing without backend
      if (window.location.hostname === 'localhost') {
         console.log("Simulating order creation for local development...");
         await new Promise(resolve => setTimeout(resolve, 2000));
         return {
            success: true,
            message: 'Vibe Captured (Simulation)',
            order_number: 'VIB-' + Math.floor(Math.random() * 100000),
            payment_url: 'https://sandbox.aamarpay.com/pay/vibe-demo'
         };
      }
      throw error;
    }
  }
};

