                  <span className="text-xs font-bold uppercase tracking-[0.3em] text-indigo-600 block mb-6">Manifest v2.0 // BD</span>
                  <h1 className="text-6xl md:text-8xl font-bold tracking-tight leading-[1.1] mb-8 uppercase">
