    name: '',
    slug: '',
    sku: '',
    description: '',
    price: 0,
    stock: 0,
    category: 'tech',
    image: 'https://images.unsplash.com/photo-1523275335684-37898b6baf30?auto=format&fit=crop&q=80&w=800'
  });

  useEffect(() => {
    loadProducts();
  }, []);

  const loadProducts = async () => {
    setIsLoading(true);
    const data = await ProductService.getAllProducts();
    setProducts(data);
    setIsLoading(false);
  };

  const handleAddProduct = async () => {
    if (!newProduct.name || !newProduct.price) return alert("Basic info required.");
    setIsLoading(true);
    await ProductService.addProduct({
      ...newProduct,
      slug: newProduct.name.toLowerCase().replace(/\s+/g, '-'),
      sku: newProduct.sku || `VB-${newProduct.category.toUpperCase()}-${Math.floor(Math.random()*1000)}`
    });
    await loadProducts();
    setIsAddingProduct(false);
    setNewProduct({
      name: '', slug: '', sku: '', description: '', price: 0, stock: 0, category: 'tech',
      image: 'https://images.unsplash.com/photo-1523275335684-37898b6baf30?auto=format&fit=crop&q=80&w=800'
    });
  };

  const handleUpdateStock = async (id: number, newStock: number) => {
    await ProductService.updateProduct(id, { stock: newStock });
    setProducts(prev => prev.map(p => p.id === id ? { ...p, stock: newStock } : p));
  };

  const handleDeleteProduct = async (id: number) => {
    if (!confirm("Delete this archive entry?")) return;
    await ProductService.deleteProduct(id);
    setProducts(prev => prev.filter(p => p.id !== id));
  };

  const handleMagicWrite = async () => {
    if (!newProduct.name) return alert("Enter a name first.");
    setIsGeneratingDescription(true);
    const desc = await generateSmartDescription(newProduct.name);
    setNewProduct(prev => ({ ...prev, description: desc }));
    setIsGeneratingDescription(false);
  };

