import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-presence';
import { X, ShieldCheck, MapPin, Phone, User, Loader2, CreditCard, Plus, Minus, Trash2, ChevronDown } from 'lucide-react';
import { CartItem } from '../types';

interface CheckoutModalProps {
  isOpen: boolean;
  onClose: () => void;
  items: CartItem[];
  onUpdateQuantity: (id: number, delta: number) => void;
  onSubmit: (data: any) => Promise<void>;
}

const CheckoutModal: React.FC<CheckoutModalProps> = ({ isOpen, onClose, items, onUpdateQuantity, onSubmit }) => {
  const [loading, setLoading] = useState(false);
  const [formData, setFormData] = useState({
    customer_name: '',
    phone: '',
    address: '',
    area: 'Inside Dhaka'
  });

  const subtotal = items.reduce((sum, item) => sum + (item.sale_price || item.price) * item.quantity, 0);
  const shipping = formData.area === 'Inside Dhaka' ? 60 : 120;
  const total = subtotal + shipping;

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (items.length === 0) return;
    setLoading(true);
    try {
      await onSubmit(formData);
    } catch (err) {
      alert("Checkout failed. Check your data.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <AnimatePresence>
      {isOpen && (
        <div className="fixed inset-0 z-[300] flex items-center justify-center p-4 sm:p-6 overflow-y-auto sm:overflow-hidden">
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            onClick={onClose}
            className="absolute inset-0 bg-slate-900/60 backdrop-blur-md"
          />
          <motion.div
            initial={{ scale: 0.95, opacity: 0, y: 10 }}
            animate={{ scale: 1, opacity: 1, y: 0 }}
            exit={{ scale: 0.95, opacity: 0, y: 10 }}
            className="relative w-full max-w-6xl bg-white rounded-3xl md:rounded-[3rem] shadow-2xl overflow-hidden flex flex-col md:flex-row max-h-[95vh] md:max-h-[90vh]"
          >
            {/* Form Section */}
            <div className="flex-1 p-8 md:p-14 lg:p-20 overflow-y-auto">
              <div className="flex items-center justify-between mb-10 md:mb-14">
                <h2 className="text-2xl md:text-4xl font-black tracking-tighter uppercase italic">Checkout</h2>
                <div className="flex items-center gap-2 text-emerald-500 bg-emerald-50 px-4 py-1.5 rounded-full">
                  <ShieldCheck size={14} />
                  <span className="text-[10px] font-black uppercase tracking-widest">SSL Secure</span>
                </div>
              </div>

              <form onSubmit={handleSubmit} className="space-y-8 md:space-y-10">
                <div className="space-y-6">
                  <div className="relative">
                    <User className="absolute left-6 top-1/2 -translate-y-1/2 text-slate-300" size={18} />
                    <input required type="text" placeholder="Recipient Name" value={formData.customer_name} onChange={(e) => setFormData({...formData, customer_name: e.target.value})} className="w-full bg-slate-50 border-none rounded-2xl py-4 md:py-5 pl-14 md:pl-16 pr-6 text-sm md:text-base font-bold outline-none focus:ring-4 focus:ring-indigo-600/5 transition-all" />
                  </div>

                  <div className="relative">
                    <Phone className="absolute left-6 top-1/2 -translate-y-1/2 text-slate-300" size={18} />
                    <input required type="tel" placeholder="Phone Number (01xxxxxxxxx)" value={formData.phone} onChange={(e) => setFormData({...formData, phone: e.target.value})} className="w-full bg-slate-50 border-none rounded-2xl py-4 md:py-5 pl-14 md:pl-16 pr-6 text-sm md:text-base font-bold outline-none focus:ring-4 focus:ring-indigo-600/5 transition-all" />
                  </div>

                  <div className="grid grid-cols-2 gap-4">
                    {['Inside Dhaka', 'Outside Dhaka'].map(area => (
                      <button
                        key={area}
                        type="button"
                        onClick={() => setFormData({...formData, area})}
                        className={`py-4 rounded-2xl text-[10px] md:text-[11px] font-black uppercase tracking-widest transition-all ${formData.area === area ? 'bg-slate-900 text-white shadow-xl' : 'bg-slate-50 text-slate-400'}`}
                      >
                        {area}
                      </button>
                    ))}
                  </div>

                  <div className="relative">
                    <MapPin className="absolute left-6 top-5 text-slate-300" size={18} />
                    <textarea required rows={3} placeholder="Full Delivery Address (Street, House, Area)" value={formData.address} onChange={(e) => setFormData({...formData, address: e.target.value})} className="w-full bg-slate-50 border-none rounded-2xl py-4 md:py-5 pl-14 md:pl-16 pr-6 text-sm md:text-base font-bold outline-none focus:ring-4 focus:ring-indigo-600/5 transition-all resize-none leading-relaxed" />
                  </div>
                </div>

                <button
                  disabled={loading || items.length === 0}
                  className="w-full bg-indigo-600 text-white py-5 md:py-7 rounded-2xl md:rounded-[2rem] font-black text-[11px] md:text-[12px] uppercase tracking-[0.4em] hover:bg-slate-900 transition-all shadow-2xl active:scale-[0.98] disabled:opacity-50 flex items-center justify-center gap-4"
                >
                  {loading ? (
                    <>
                      <Loader2 className="animate-spin" size={20} /> Securing Archive
                    </>
                  ) : (
                    <>
                      Place Order ৳{total.toLocaleString()} <CreditCard size={20} />
                    </>
                  )}
                </button>
              </form>
            </div>

