                      <p className="text-[10px] font-black text-indigo-600 mb-3">৳{(item.sale_price || item.price).toLocaleString()} × {item.quantity}</p>

                      <div className="flex items-center gap-3">
                         <button onClick={() => onUpdateQuantity(item.id, -1)} className="p-1.5 bg-white border border-slate-200 rounded-lg text-slate-400 hover:text-black transition-colors"><Minus size={12} /></button>
                         <span className="text-[11px] font-black tabular-nums">{item.quantity}</span>
                         <button onClick={() => onUpdateQuantity(item.id, 1)} className="p-1.5 bg-white border border-slate-200 rounded-lg text-slate-400 hover:text-black transition-colors"><Plus size={12} /></button>
                      </div>
                    </div>
                    <div className="text-right py-1">
                       <span className="text-[11px] md:text-[12px] font-black text-slate-900 tabular-nums">৳{((item.sale_price || item.price) * item.quantity).toLocaleString()}</span>
                    </div>
                  </div>
                ))}
              </div>

              <div className="mt-auto pt-8 border-t border-slate-200 space-y-3 md:space-y-4">
                <div className="flex justify-between text-[10px] font-black uppercase tracking-widest text-slate-400">
                  <span>Subtotal</span>
                  <span className="tabular-nums">৳{subtotal.toLocaleString()}</span>
                </div>
                <div className="flex justify-between text-[10px] font-black uppercase tracking-widest text-slate-400">
                  <span>Courier Fee ({formData.area === 'Inside Dhaka' ? 'Local' : 'Global'})</span>
                  <span className="tabular-nums">৳{shipping.toLocaleString()}</span>
                </div>
                <div className="flex justify-between items-center pt-4">
                  <span className="text-[11px] font-black uppercase tracking-widest">Total Payable</span>
                  <span className="text-2xl md:text-3xl font-black tracking-tighter text-indigo-600 tabular-nums">৳{total.toLocaleString()}</span>
                </div>
              </div>
            </div>

            <button onClick={onClose} className="absolute top-6 right-6 md:top-10 md:right-10 p-3 text-slate-300 hover:text-slate-900 transition-colors bg-white rounded-full md:bg-transparent shadow-lg md:shadow-none">
              <X size={20} md:size={24} />
            </button>
          </motion.div>
        </div>
      )}
    </AnimatePresence>
  );
};

