    if (!newProduct.name || !newProduct.price) return alert("Basic info required.");
    setIsLoading(true);
    await ProductService.addProduct({
      ...newProduct,
      slug: newProduct.name.toLowerCase().replace(/\s+/g, '-'),
      sku: newProduct.sku || `VB-${newProduct.category.toUpperCase()}-${Math.floor(Math.random()*1000)}`
    });
    await loadProducts();
    setIsAddingProduct(false);
    setNewProduct({
      name: '', slug: '', sku: '', description: '', price: 0, stock: 0, category: 'tech',
      image: 'https://images.unsplash.com/photo-1523275335684-37898b6baf30?auto=format&fit=crop&q=80&w=800'
    });
  };

