                    <Search className="absolute left-6 top-1/2 -translate-y-1/2 text-slate-300" size={18} />
                    <input 
                      type="text" 
                      placeholder="SEARCH ORDER ID, NAME, OR PHONE..." 
                      value={orderSearch}
                      onChange={(e) => setOrderSearch(e.target.value)}
                      className="w-full bg-slate-50 border-none rounded-2xl py-4 pl-16 pr-6 text-[11px] font-black tracking-widest placeholder:text-slate-200 focus:ring-4 focus:ring-indigo-600/5 transition-all outline-none uppercase"
                    />
                  </div>
               </div>

               {/* Advanced Order Table */}
               <div className="bg-white rounded-[3rem] border border-slate-100 shadow-sm overflow-hidden">
                 <div className="overflow-x-auto scrollbar-hide">
                    <table className="w-full text-left min-w-[1000px]">
                      <thead>
                        <tr className="bg-slate-50/50 border-b border-slate-100">
                          <th className="px-10 py-8 text-[10px] font-black text-slate-400 uppercase tracking-widest italic">Order Node</th>
                          <th className="px-10 py-8 text-[10px] font-black text-slate-400 uppercase tracking-widest italic">Customer Architecture</th>
                          <th className="px-10 py-8 text-[10px] font-black text-slate-400 uppercase tracking-widest italic">Status Phase</th>
                          <th className="px-10 py-8 text-[10px] font-black text-slate-400 uppercase tracking-widest italic text-right">Value (৳)</th>
                          <th className="px-10 py-8 text-[10px] font-black text-slate-400 uppercase tracking-widest italic text-right">Execution</th>
                        </tr>
                      </thead>
                      <tbody className="divide-y divide-slate-50">
                        {filteredOrders.map(order => (
                          <tr key={order.id} className="group hover:bg-slate-50/30 transition-all">
                            <td className="px-10 py-8">
                               <p className="text-sm font-black text-indigo-600 tracking-widest uppercase mb-1">{order.orderNumber}</p>
                               <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">{order.createdAt}</p>
                            </td>
                            <td className="px-10 py-8">
                               <p className="text-sm font-black text-slate-900 uppercase italic tracking-tight mb-1">{order.customerName}</p>
                               <div className="flex items-center gap-3 text-slate-400">
                                  <Phone size={12} /> <span className="text-[10px] font-bold tabular-nums">{order.phone}</span>
                               </div>
                            </td>
                            <td className="px-10 py-8">
                               <div className="flex items-center gap-3">
                                  <div className={`w-2.5 h-2.5 rounded-full animate-pulse ${
                                    order.shippingStatus === ShippingStatus.PENDING ? 'bg-amber-400' :
                                    order.shippingStatus === ShippingStatus.PROCESSING ? 'bg-indigo-500' :
                                    order.shippingStatus === ShippingStatus.SHIPPED ? 'bg-blue-500' : 'bg-emerald-500'
                                  }`} />
                                  <span className="text-[10px] font-black uppercase tracking-widest text-slate-900">{order.shippingStatus}</span>
                               </div>
                            </td>
                            <td className="px-10 py-8 text-right">
                               <p className="text-base font-black text-slate-900 tracking-tighter italic">৳{order.totalAmount.toLocaleString()}</p>
                               <span className={`text-[8px] font-black uppercase tracking-widest ${order.paymentStatus === 'paid' ? 'text-emerald-500' : 'text-amber-500'}`}>
                                 {order.paymentStatus}
                               </span>
                            </td>
                            <td className="px-10 py-8 text-right">
                               <div className="flex justify-end gap-2">
                                  <button onClick={() => setSelectedOrder(order)} className="p-3 bg-slate-50 text-slate-400 rounded-xl hover:bg-slate-900 hover:text-white transition-all">
                                    <Eye size={16} />
                                  </button>
                                  <a href={`https://wa.me/${order.phone}`} target="_blank" className="p-3 bg-emerald-50 text-emerald-500 rounded-xl hover:bg-emerald-500 hover:text-white transition-all">
                                    <Phone size={16} />
                                  </a>
                               </div>
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                 </div>
               </div>
            </motion.div>
          )}

          {activeTab === 'products' && (
             <div className="space-y-10 md:space-y-12">
               {/* Products view... */}
               <div className="bg-white rounded-[3rem] border border-slate-100 shadow-sm p-12 text-center text-slate-300 font-black uppercase tracking-[0.4em] italic">
                 Warehousing Interface Operational
               </div>
             </div>
          )}
        </div>
      </main>

      {/* Order Details Command Modal */}
      <AnimatePresence>
        {selectedOrder && (
          <div className="fixed inset-0 z-[500] flex items-center justify-center p-4 sm:p-8">
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} onClick={() => setSelectedOrder(null)} className="absolute inset-0 bg-slate-950/70 backdrop-blur-xl" />
            <motion.div initial={{ scale: 0.9, opacity: 0, y: 20 }} animate={{ scale: 1, opacity: 1, y: 0 }} exit={{ scale: 0.9, opacity: 0, y: 20 }} className="relative w-full max-w-6xl bg-white rounded-[3rem] md:rounded-[4rem] shadow-3xl overflow-hidden flex flex-col lg:flex-row h-[90vh] lg:h-auto overflow-y-auto">

               {/* Order Recap */}
               <div className="w-full lg:w-[400px] bg-slate-50/50 p-10 md:p-14 border-b lg:border-b-0 lg:border-r border-slate-100 flex flex-col">
                  <div className="mb-12">
                     <span className="text-[10px] font-black text-indigo-600 uppercase tracking-[0.4em] italic mb-4 block">Archive Identification</span>
                     <h2 className="text-4xl font-black tracking-tighter uppercase italic text-slate-900">{selectedOrder.orderNumber}</h2>
                     <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-2">Captured on {selectedOrder.createdAt}</p>
                  </div>

                  <div className="flex-1 space-y-8 overflow-y-auto pr-2 scrollbar-hide">
                     <div>
                        <p className="text-[9px] font-black text-slate-300 uppercase tracking-widest mb-4">Payload (Items)</p>
                        <div className="space-y-6">
                           {selectedOrder.items.length > 0 ? selectedOrder.items.map((item, i) => (
                             <div key={i} className="flex gap-4">
                               <div className="w-16 h-20 bg-white rounded-xl overflow-hidden border border-slate-100 p-1">
                                 <img src={item.image} className="w-full h-full object-cover rounded-lg" />
                               </div>
                               <div className="flex-1 min-w-0">
                                 <p className="text-[11px] font-black uppercase truncate text-slate-900">{item.name}</p>
                                 <p className="text-[10px] font-bold text-indigo-600 italic">৳{item.price.toLocaleString()} × {item.quantity}</p>
                               </div>
                             </div>
                           )) : (
                             <p className="text-[10px] font-bold text-slate-400 italic">No artifact data found for this entry.</p>
                           )}
                        </div>
                     </div>
                  </div>

                  <div className="pt-10 border-t border-slate-200 mt-10">
                    <div className="flex justify-between items-end">
                       <div>
                         <p className="text-[9px] font-black text-slate-300 uppercase tracking-widest mb-1">Settlement Total</p>
                         <p className="text-3xl font-black text-slate-900 tracking-tighter italic">৳{selectedOrder.totalAmount.toLocaleString()}</p>
                       </div>
                       <div className={`px-4 py-1.5 rounded-full text-[9px] font-black uppercase tracking-widest ${selectedOrder.paymentStatus === 'paid' ? 'bg-emerald-50 text-emerald-600' : 'bg-amber-50 text-amber-600'}`}>
                         {selectedOrder.paymentStatus}
                       </div>
                    </div>
                  </div>
               </div>

               {/* Command Area */}
               <div className="flex-1 p-10 md:p-16 flex flex-col justify-between space-y-12">
                  <div className="flex justify-between items-start">
                    <div>
                       <h3 className="text-2xl font-black tracking-tighter uppercase italic">Customer Protocol</h3>
                       <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-1">Delivery Synchronization</p>
                    </div>
                    <button onClick={() => setSelectedOrder(null)} className="p-4 bg-slate-50 text-slate-300 rounded-2xl hover:text-rose-500 transition-colors">
                      <X size={24} />
                    </button>
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                     <div className="space-y-8">
                        <div>
                           <label className="text-[9px] font-black uppercase tracking-widest text-slate-300 ml-1">Recipient Name</label>
                           <p className="text-lg font-black text-slate-900 uppercase italic tracking-tight">{selectedOrder.customerName}</p>
                        </div>
                        <div>
                           <label className="text-[9px] font-black uppercase tracking-widest text-slate-300 ml-1">Contact Channel</label>
                           <p className="text-lg font-black text-slate-900 tabular-nums">{selectedOrder.phone}</p>
                        </div>
                        <div>
                           <label className="text-[9px] font-black uppercase tracking-widest text-slate-300 ml-1">Destination Address</label>
                           <p className="text-sm font-bold text-slate-500 italic leading-relaxed">{selectedOrder.address}, {selectedOrder.area}</p>
                        </div>
                     </div>

                     <div className="space-y-10">
                        <div>
                           <label className="text-[9px] font-black uppercase tracking-widest text-slate-300 ml-1 block mb-4">Phase Transitions</label>
                           <div className="grid grid-cols-2 gap-3">
                              {Object.values(ShippingStatus).map(s => (
                                <button 
                                  key={s}
                                  onClick={() => updateOrderStatus(selectedOrder.id, s)}
                                  className={`py-3 rounded-xl text-[9px] font-black uppercase tracking-widest transition-all ${selectedOrder.shippingStatus === s ? 'bg-slate-900 text-white shadow-lg scale-105' : 'bg-slate-50 text-slate-400 hover:bg-slate-100'}`}
                                >
                                  {s}
                                </button>
                              ))}
                           </div>
                        </div>

                        <div className="bg-slate-50 p-8 rounded-3xl border border-slate-100">
                           <div className="flex items-center gap-3 mb-6">
                              <Truck size={18} className="text-indigo-600" />
                              <span className="text-[10px] font-black uppercase tracking-widest italic">Courier Linkage</span>
                           </div>
                           <div className="relative group">
                              <Send className="absolute right-6 top-1/2 -translate-y-1/2 text-slate-200 group-focus-within:text-indigo-600" size={16} />
                              <input 
                                type="text" 
                                placeholder="SYNC TRACKING ID (STEAD-XX)"
                                className="w-full bg-white border-none rounded-xl py-4 px-6 text-[10px] font-black tracking-widest outline-none focus:ring-4 focus:ring-indigo-600/5 transition-all"
                              />
                           </div>
                           <button className="w-full mt-4 bg-indigo-600 text-white py-4 rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-slate-900 transition-all shadow-xl active:scale-95">
                             Sync Logistics
                           </button>
                        </div>
                     </div>
                  </div>

                  <div className="flex flex-col sm:flex-row gap-4 pt-10 border-t border-slate-50">
                     <button className="flex-1 bg-white border border-slate-100 py-5 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-slate-50 transition-all flex items-center justify-center gap-3">
                       <ExternalLink size={16} /> Print Manifesto
                     </button>
                     <button onClick={() => setSelectedOrder(null)} className="flex-1 bg-slate-900 text-white py-5 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-indigo-600 transition-all shadow-xl">
                       Close Protocol
                     </button>
                  </div>
               </div>

            </motion.div>
          </div>
        )}
      </AnimatePresence>
    </div>
  );
};

export default AdminPanel;
